// Park-spezifische Detailzeilen aus OSM-Tags aufbereiten
function parkenInfo(tags) {
  if (!tags) return [];
  const zeilen = [];
  const typMap = { surface:'Parkplatz (ebenerdig)', underground:'Tiefgarage', 'multi-storey':'Parkhaus', rooftop:'Dachparkplatz', street_side:'Parken am Straßenrand', lane:'Parkstreifen' };
  if (tags.parking && typMap[tags.parking]) zeilen.push('🏗️ ' + typMap[tags.parking]);
  if (tags.fee === 'yes')      zeilen.push('💶 Gebührenpflichtig' + (tags.charge ? ' — ' + tags.charge : ''));
  else if (tags.fee === 'no')  zeilen.push('✅ Kostenlos');
  if (tags.capacity && /^\d+$/.test(tags.capacity)) zeilen.push('🚗 ' + tags.capacity + ' Stellplätze');
  if (tags['capacity:disabled'] && /^\d+$/.test(tags['capacity:disabled'])) zeilen.push('♿ ' + tags['capacity:disabled'] + ' Behindertenparkplätze');
  if (tags.maxstay)              zeilen.push('⏱️ Höchstparkdauer: ' + tags.maxstay);
  if (tags.access === 'customers') zeilen.push('🛒 Nur für Kunden');
  else if (tags.access === 'permit') zeilen.push('🎫 Nur mit Genehmigung');
  if (tags.opening_hours && tags.opening_hours !== '24/7') zeilen.push('🕐 ' + tags.opening_hours);
  else if (tags.opening_hours === '24/7') zeilen.push('🕐 Rund um die Uhr geöffnet');
  return zeilen;
}

function initKarte() {
  const mapEl = el('karte');
  if (!mapEl || !state.umgebungStandort || typeof L === 'undefined') return;
  if (mapEl.textContent.includes('Standort eingeben')) return;

  const { lat, lng } = state.umgebungStandort;

  // Alte Karte entfernen
  if (state.karte) { state.karte.remove(); state.karte = null; }

  // Neue Karte
  const karte = L.map('karte').setView([lat, lng], 14);
  state.karte = karte;

  L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
    attribution: '© <a href="https://www.openstreetmap.org/">OpenStreetMap</a>',
    maxZoom: 19
  }).addTo(karte);

  // Eigener Standort-Marker
  const eigenerMarker = L.divIcon({
    html: '<div style="background:#4F46E5;width:16px;height:16px;border-radius:50%;border:3px solid white;box-shadow:0 2px 8px rgba(79,70,229,.6)"></div>',
    iconSize: [16,16], iconAnchor: [8,8], className: ''
  });
  L.marker([lat, lng], { icon: eigenerMarker }).addTo(karte).bindPopup('<strong>📍 Ihr Standort</strong>');

  state.markerSchicht = L.layerGroup().addTo(karte);
  state.routeSchicht  = L.layerGroup().addTo(karte);

  // Gespeicherte Route wieder anzeigen
  if (state.routeDaten?.geoJson) {
    L.geoJSON(state.routeDaten.geoJson, { style: { color: '#4F46E5', weight: 5, opacity: .75 } }).addTo(state.routeSchicht);
    karte.fitBounds(L.geoJSON(state.routeDaten.geoJson).getBounds(), { padding: [30,30] });
  }

  // Orte laden
  ladeOrte(karte);
}

async function ladeOrte(karte) {
  // Im Routenplaner-Modus keine POIs laden
  if (state.umgebungKat === 'route') return;
  const kat = OVERPASS_KAT[state.umgebungKat];
  if (!kat || !state.umgebungStandort) return;

  const { lat, lng } = state.umgebungStandort;
  const radius = state.umgebungRadius || kat.r;
  const query = kat.query.replace(/\{r\}/g, radius).replace(/\{lat\}/g, lat).replace(/\{lng\}/g, lng);
  const overpassQ = `[out:json][timeout:25];(${query});out center;`;

  // Loading-State in Sidebar
  const liste = el('ort-liste');
  const titelEl = el('sidebar-titel');
  const subEl = el('sidebar-sub');
  if (liste) liste.innerHTML = '<div class="loading-spinner"><div class="spinner"></div><span>Suche läuft...</span></div>';

  try {
    const res = await fetch(`https://overpass-api.de/api/interpreter?data=${encodeURIComponent(overpassQ)}`);
    // Overpass liefert bei Ueberlastung HTTP 200 mit XML-Fehlerseite — JSON-Parse absichern
    const rohtext = await res.text();
    let daten;
    try { daten = JSON.parse(rohtext); }
    catch { throw new Error('Karten-Dienst überlastet'); }
    const orte = daten.elements || [];
    // Flächen (ways/relations, z.B. Parkplätze) liefern die Koordinate als center
    orte.forEach(o => { if (o.lat == null && o.center) { o.lat = o.center.lat; o.lon = o.center.lon; } });

    // Marker hinzufügen
    if (state.markerSchicht) state.markerSchicht.clearLayers();

    // Entfernung berechnen & sortieren (nur Nodes mit Koordinaten)
    const mitEntfernung = orte
      .filter(o => o.lat && o.lon)
      .map(o => ({
        ...o,
        distanz: Math.round(haversine(lat, lng, o.lat, o.lon))
      })).sort((a,b) => a.distanz - b.distanz).slice(0,30);

    mitEntfernung.forEach(o => {
      const name = o.tags?.name || o.tags?.brand || (state.umgebungKat==='parken' ? 'Parkplatz' : 'Unbekannt');
      const icon = L.divIcon({
        html: `<div style="background:${kat.farbe};color:white;width:32px;height:32px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:15px;box-shadow:0 2px 8px rgba(0,0,0,.3);border:2px solid white">${kat.icon}</div>`,
        iconSize: [32,32], iconAnchor: [16,16], className: ''
      });
      const m = L.marker([o.lat, o.lon], { icon }).addTo(state.markerSchicht);
      const website = o.tags?.website || o.tags?.['contact:website'] || '';
      const phone   = o.tags?.phone   || o.tags?.['contact:phone']   || '';
      const oeffnung = o.tags?.opening_hours || '';
      const kueche  = o.tags?.cuisine || '';
      const istGastro = ['restaurant','cafe','imbiss','baeckerei'].includes(state.umgebungKat);
      const menuLink = o.tags?.['menu:url'] || o.tags?.menu || '';
      const speisekarteSuche = istGastro && !menuLink
        ? `https://www.google.com/search?q=${encodeURIComponent(name + ' ' + (o.tags?.['addr:city'] || '') + ' Speisekarte')}`
        : '';
      const popup = `<div class="popup-name">${esc(name)}</div>
        <div class="popup-info">${o.distanz < 1000 ? o.distanz+'m' : (o.distanz/1000).toFixed(1)+'km'} entfernt</div>
        ${o.tags?.['addr:street'] ? `<div class="popup-info">${esc(o.tags['addr:street'])} ${esc(o.tags['addr:housenumber']||'')}</div>` : ''}
        ${state.umgebungKat==='parken' ? parkenInfo(o.tags).map(z=>`<div class="popup-info">${esc(z)}</div>`).join('') : ''}
        ${kueche ? `<div class="popup-info">🍴 ${esc(kueche.replace(/;/g,', '))}</div>` : ''}
        ${oeffnung ? `<div class="popup-info">🕐 ${esc(oeffnung)}</div>` : ''}
        ${phone ? `<a href="tel:${esc(phone.replace(/\s/g,''))}" class="popup-link">📞 ${esc(phone)}</a>` : ''}
        ${website ? `<a href="${esc(website)}" target="_blank" rel="noopener" onclick="return linkOeffnen(this.href)" class="popup-link">🌐 Website öffnen</a>` : ''}
        ${menuLink ? `<a href="${esc(menuLink)}" target="_blank" rel="noopener" data-extern="1" onclick="return linkOeffnen(this.href)" class="popup-link">📋 Speisekarte ansehen</a>` : ''}
        ${speisekarteSuche ? `<a href="${esc(speisekarteSuche)}" target="_blank" rel="noopener" data-extern="1" onclick="return linkOeffnen(this.href)" class="popup-link">📋 Speisekarte suchen</a>` : ''}
        <a href="https://www.google.com/maps/dir/?api=1&destination=${o.lat},${o.lon}" target="_blank" rel="noopener" data-extern="1" onclick="return linkOeffnen(this.href)" class="popup-link popup-navi">🗺️ Route planen (Google Maps)</a>`;
      m.bindPopup(popup);
    });

    // Sidebar befüllen
    if (titelEl) titelEl.textContent = `${kat.icon} ${mitEntfernung.length} gefunden`;
    if (subEl) subEl.textContent = `im Umkreis von ${formatRadius(radius)}`;
    if (liste) {
      if (mitEntfernung.length === 0) {
        liste.innerHTML = `<div class="ort-leer">Keine Ergebnisse in ${formatRadius(radius)} gefunden.</div>`;
      } else {
        const istGastro = ['restaurant','cafe','imbiss','baeckerei'].includes(state.umgebungKat);
        liste.innerHTML = mitEntfernung.map(o => {
          const name = o.tags?.name || o.tags?.brand || (state.umgebungKat==='parken' ? 'Parkplatz' : 'Unbekannt');
          const strasse = o.tags?.['addr:street'] ? `${o.tags['addr:street']} ${o.tags['addr:housenumber']||''}` : '';
          const dist = o.distanz < 1000 ? `${o.distanz} m` : `${(o.distanz/1000).toFixed(1)} km`;
          const website = o.tags?.website || o.tags?.['contact:website'] || '';
          const phone = o.tags?.phone || o.tags?.['contact:phone'] || '';
          const kueche = o.tags?.cuisine || '';
          const oeffnung = o.tags?.opening_hours || '';
          const menuLink = o.tags?.['menu:url'] || o.tags?.menu || '';
          const speisekarteSuche = istGastro && !menuLink
            ? `https://www.google.com/search?q=${encodeURIComponent(name + ' ' + (o.tags?.['addr:city'] || '') + ' Speisekarte')}`
            : '';
          return `<div class="ort-item">
            <div class="ort-row" onclick="karteFliegen(${o.lat},${o.lon})">
              <div class="ort-icon" style="background:${kat.bg};color:${kat.farbe}">${kat.icon}</div>
              <div class="ort-info">
                <div class="ort-name">${esc(name)}</div>
                ${strasse ? `<div class="ort-adresse">${esc(strasse)}</div>` : ''}
                ${state.umgebungKat==='parken' ? parkenInfo(o.tags).map(z=>`<div class="ort-adresse">${esc(z)}</div>`).join('') : ''}
                ${kueche ? `<div class="ort-adresse">🍴 ${esc(kueche.replace(/;/g,', '))}</div>` : ''}
                ${oeffnung ? `<div class="ort-adresse">🕐 ${esc(oeffnung)}</div>` : ''}
                <div class="ort-dist">📏 ${dist} entfernt</div>
                ${(website || phone || menuLink || speisekarteSuche) ? `<div class="ort-links">
                  ${website ? `<a href="${esc(website)}" target="_blank" rel="noopener" onclick="event.stopPropagation();return linkOeffnen(this.href)" class="ort-link">🌐 Web</a>` : ''}
                  ${phone ? `<a href="tel:${esc(phone.replace(/\s/g,''))}" onclick="event.stopPropagation()" class="ort-link">📞 Anruf</a>` : ''}
                  ${menuLink ? `<a href="${esc(menuLink)}" target="_blank" rel="noopener" data-extern="1" onclick="event.stopPropagation();return linkOeffnen(this.href)" class="ort-link">📋 Speisekarte</a>` : ''}
                  ${speisekarteSuche ? `<a href="${esc(speisekarteSuche)}" target="_blank" rel="noopener" data-extern="1" onclick="event.stopPropagation();return linkOeffnen(this.href)" class="ort-link">📋 Speisekarte</a>` : ''}
                </div>` : ''}
              </div>
            </div>
            <button class="ort-route-btn" onclick="ortRouteOeffnen(${o.lat},${o.lon},'${esc(name).replace(/'/g,"&#39;")}')">
              🗺️ Route
            </button>
          </div>`;
        }).join('');
      }
    }
  } catch(e) {
    const ueberlastet = /überlastet/.test(e.message || '');
    if (liste) liste.innerHTML = `<div class="ort-leer">⚠️ ${ueberlastet ? 'Der Karten-Dienst ist gerade überlastet — bitte in 1–2 Minuten erneut versuchen.' : 'Fehler beim Laden. Bitte erneut versuchen.'}</div>`;
    console.warn('Umgebungssuche:', e.message || e);
  }
}

function karteFliegen(lat, lng) {
  if (state.karte) state.karte.flyTo([lat, lng], 16);
}

// Externen Link zuverlässig öffnen — auch in der installierten App (PWA),
// wo normale target="_blank"-Links oft nicht reagieren.
function linkOeffnen(url) {
  if (url) {
    try {
      const w = window.open(url, '_blank', 'noopener');
      if (!w) location.href = url; // Popup blockiert → im selben Fenster öffnen
    } catch (e) {
      location.href = url;
    }
  }
  return false; // verhindert das Standard-Verhalten des <a>, kein Doppel-Öffnen
}

function haversine(lat1, lng1, lat2, lng2) {
  const R = 6371000, φ1 = lat1*Math.PI/180, φ2 = lat2*Math.PI/180;
  const Δφ = (lat2-lat1)*Math.PI/180, Δλ = (lng2-lng1)*Math.PI/180;
  const a = Math.sin(Δφ/2)**2 + Math.cos(φ1)*Math.cos(φ2)*Math.sin(Δλ/2)**2;
  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
}

function renderMultiRoute(standort) {
  const m = state.routeMultiModi;
  if (!m) return '';
  if (m.laden) return '<div class="route-multi-laden"><div class="spinner"></div><span>Routen werden für Auto, Fahrrad und Fußweg berechnet...</span></div>';
  if (!m.ergebnisse || Object.keys(m.ergebnisse).length === 0) {
    return '<div class="route-box" style="border-color:#DC2626"><div style="color:#DC2626;font-weight:700">⚠️ Keine Route berechnet werden konnte.</div></div>';
  }
  const aktiv = state.routeAktivProfil || 'auto';
  const profile = [
    { id:'auto',    icon:'🚗', label:'Auto',    farbe:'#4F46E5' },
    { id:'fahrrad', icon:'🚴', label:'Fahrrad', farbe:'#059669' },
    { id:'fuss',    icon:'🚶', label:'Zu Fuß',  farbe:'#D97706' }
  ];
  const startStr = encodeURIComponent(standort?.name || '');
  const zielStr  = encodeURIComponent(m.ziel || '');

  return `
  <div class="multi-route-box">
    <div class="multi-route-titel">🗺️ Route nach <strong>${esc(m.ziel)}</strong></div>
    <div class="multi-route-modi">
      ${profile.map(p => {
        const erg = m.ergebnisse[p.id];
        const aktivClass = aktiv===p.id ? 'aktiv' : '';
        if (!erg) return `<div class="multi-modus disabled">
          <div class="multi-modus-icon">${p.icon}</div>
          <div class="multi-modus-label">${p.label}</div>
          <div class="multi-modus-info">–</div>
        </div>`;
        return `
        <button class="multi-modus ${aktivClass}" onclick="routeProfilWechseln('${p.id}')" style="--mr-farbe:${p.farbe}">
          <div class="multi-modus-icon">${p.icon}</div>
          <div class="multi-modus-label">${p.label}</div>
          <div class="multi-modus-dauer">${erg.dauer}</div>
          <div class="multi-modus-dist">${erg.distanz}</div>
        </button>`;
      }).join('')}
      <a href="https://www.google.com/maps/dir/?api=1&origin=${startStr}&destination=${m.lat},${m.lng}&travelmode=transit"
         target="_blank" class="multi-modus oepnv">
        <div class="multi-modus-icon">🚌</div>
        <div class="multi-modus-label">ÖPNV</div>
        <div class="multi-modus-dauer">Bus & Bahn</div>
        <div class="multi-modus-dist">Google öffnen →</div>
      </a>
    </div>
    <div class="multi-route-actions">
      <button class="btn btn-primary btn-sm" onclick="naviStarten('${aktiv}')">🧭 Navigation starten</button>
      <a href="https://www.google.com/maps/dir/?api=1&origin=${startStr}&destination=${m.lat},${m.lng}" target="_blank" class="btn btn-outline btn-sm">📱 Google Maps</a>
      <button class="btn btn-outline btn-sm" onclick="routeZurücksetzen();render()">✕ Route schließen</button>
    </div>
    <div style="font-size:.72rem;color:var(--g500);margin-top:.4rem;text-align:center">🧭 Navigation mit Sprachansagen — am besten als App auf dem Handy-Bildschirm nutzen</div>
  </div>`;
}

// ===== ROUTENPLANER =====
function routenplanerToggle() {
  state.umgebungRouteModus = !state.umgebungRouteModus;
  if (!state.umgebungRouteModus) routeZurücksetzen();
  render();
}

function routeZurücksetzen() {
  state.routeDaten = null;
  state.routeMultiModi = null;
  if (state.routeSchicht) state.routeSchicht.clearLayers();
}

// Aus POI-Sidebar: direkt Route zum Restaurant/Geschäft mit allen Transportmitteln
function ortRouteOeffnen(zielLat, zielLng, zielName) {
  state.umgebungKat = 'route';
  state.routeZiel = zielName;
  state.routeZielKoord = { lat: zielLat, lng: zielLng };
  render();
  setTimeout(() => routeMultiBerechnen(zielLat, zielLng, zielName), 250);
}

async function routeMultiBerechnen(zielLat, zielLng, zielName) {
  const standort = state.umgebungStandort;
  if (!standort) return;
  state.routeLaden = true;
  state.routeMultiModi = { laden: true, ergebnisse: null, ziel: zielName };
  render();

  // Im Routenplaner zeichnet initRoutenplanerKarte() die Route nach dem render() —
  // hier nur für die Umgebungs-Sektion direkt auf die Karte zeichnen.
  const aufKarteZeichnen = state.sektion !== 'routenplaner';

  // Karte zentrieren & Marker setzen
  if (aufKarteZeichnen && state.routeSchicht) state.routeSchicht.clearLayers();
  if (aufKarteZeichnen && state.karte) {
    const zielIcon = L.divIcon({
      html: '<div style="background:#DC2626;width:14px;height:14px;border-radius:50%;border:3px solid white;box-shadow:0 2px 8px rgba(220,38,38,.6)"></div>',
      iconSize:[14,14], iconAnchor:[7,7], className:''
    });
    L.marker([zielLat, zielLng], {icon: zielIcon}).addTo(state.routeSchicht);
  }

  // Drei OSRM-Profile parallel abfragen
  const profile = ['driving', 'cycling', 'foot'];
  const requests = profile.map(p =>
    fetch(`https://router.project-osrm.org/route/v1/${p}/${standort.lng},${standort.lat};${zielLng},${zielLat}?overview=full&geometries=geojson`, { signal: AbortSignal.timeout(15000) })
      .then(r => r.ok ? r.json() : null).catch(() => null)
  );
  const [auto, fahrrad, fuss] = await Promise.all(requests);

  const farben = { auto:'#4F46E5', fahrrad:'#059669', fuss:'#D97706' };
  const ergebnisse = {};
  [['auto', auto], ['fahrrad', fahrrad], ['fuss', fuss]].forEach(([key, data]) => {
    if (data?.code === 'Ok' && data.routes?.length) {
      const r = data.routes[0];
      ergebnisse[key] = {
        distanz: r.distance < 1000 ? `${Math.round(r.distance)} m` : `${(r.distance/1000).toFixed(1)} km`,
        dauer: r.duration < 60 ? `${Math.round(r.duration)} Sek.` : r.duration < 3600 ? `${Math.round(r.duration/60)} Min.` : `${Math.floor(r.duration/3600)}h ${Math.round((r.duration%3600)/60)} Min.`,
        geoJson: r.geometry,
        farbe: farben[key]
      };
    }
  });

  // Schnellste Route auf der Karte zeichnen (nur Umgebungs-Sektion)
  const aktivProfil = state.routeAktivProfil || 'auto';
  if (aufKarteZeichnen && ergebnisse[aktivProfil] && state.karte) {
    const layer = L.geoJSON(ergebnisse[aktivProfil].geoJson, { style: { color: ergebnisse[aktivProfil].farbe, weight: 5, opacity: .85 } }).addTo(state.routeSchicht);
    state.karte.fitBounds(layer.getBounds(), { padding: [40, 40], animate: false });
  }

  state.routeMultiModi = { laden: false, ergebnisse, ziel: zielName, lat: zielLat, lng: zielLng };
  state.routeLaden = false;
  render();
}

function routeProfilWechseln(profil) {
  state.routeAktivProfil = profil;
  const erg = state.routeMultiModi?.ergebnisse?.[profil];
  if (!erg || !state.karte) { render(); return; }
  if (state.routeSchicht) {
    state.routeSchicht.clearLayers();
    // Ziel-Marker neu setzen
    if (state.routeMultiModi.lat) {
      const zielIcon = L.divIcon({
        html: '<div style="background:#DC2626;width:14px;height:14px;border-radius:50%;border:3px solid white;box-shadow:0 2px 8px rgba(220,38,38,.6)"></div>',
        iconSize:[14,14], iconAnchor:[7,7], className:''
      });
      L.marker([state.routeMultiModi.lat, state.routeMultiModi.lng], {icon: zielIcon}).addTo(state.routeSchicht);
    }
    const layer = L.geoJSON(erg.geoJson, { style: { color: erg.farbe, weight: 5, opacity: .85 } }).addTo(state.routeSchicht);
    state.karte.fitBounds(layer.getBounds(), { padding: [40, 40] });
  }
  render();
}

// ===== NAVIGATIONSGERÄT (Turn-by-Turn mit Live-GPS und Sprachansagen) =====
let _naviOverlayEl = null;
const _NAVI_PROFIL_OSRM = { auto:'driving', fahrrad:'cycling', fuss:'foot' };

// OSRM-Manöver in eine deutsche Anweisung übersetzen
function naviAnweisung(step) {
  const t = step?.maneuver?.type || '';
  const mod = step?.maneuver?.modifier || '';
  const strasse = step?.name || '';
  const richtung = {
    'left':'links','slight left':'leicht links','sharp left':'scharf links',
    'right':'rechts','slight right':'leicht rechts','sharp right':'scharf rechts',
    'straight':'geradeaus','uturn':'wenden'
  }[mod] || '';
  const aufStr = strasse ? ' auf ' + strasse : '';
  if (t === 'depart')  return strasse ? 'Losfahren auf ' + strasse : 'Losfahren';
  if (t === 'arrive')  return 'Sie haben Ihr Ziel erreicht';
  if (t === 'roundabout' || t === 'rotary')
    return step.maneuver.exit ? 'Im Kreisverkehr die ' + step.maneuver.exit + '. Ausfahrt nehmen' : 'Dem Kreisverkehr folgen';
  if (t === 'merge')    return 'Einfädeln' + aufStr;
  if (t === 'on ramp')  return 'Auffahrt nehmen' + aufStr;
  if (t === 'off ramp') return 'Abfahrt nehmen' + (richtung && richtung!=='geradeaus' ? ' (' + richtung + ')' : '');
  if (t === 'fork')     return 'An der Gabelung ' + (richtung || 'geradeaus') + ' halten';
  if (t === 'end of road') return 'Am Ende der Straße ' + (richtung || 'weiterfahren') + aufStr;
  if (t === 'continue' || t === 'new name') return strasse ? 'Weiter auf ' + strasse : 'Geradeaus weiter';
  if (t === 'turn') {
    if (mod === 'straight') return 'Geradeaus weiter' + aufStr;
    if (mod === 'uturn')    return 'Bitte wenden';
    if (richtung)           return richtung.charAt(0).toUpperCase() + richtung.slice(1) + ' abbiegen' + aufStr;
  }
  return strasse ? 'Weiter auf ' + strasse : 'Der Route folgen';
}

function naviIcon(step) {
  const t = step?.maneuver?.type || '';
  const mod = step?.maneuver?.modifier || '';
  if (t === 'arrive') return '🏁';
  if (t === 'depart') return '🚩';
  if (t === 'roundabout' || t === 'rotary') return '🔄';
  if (mod === 'uturn') return '🔃';
  if (mod.includes('left'))  return '⬅️';
  if (mod.includes('right')) return '➡️';
  return '⬆️';
}

function naviDistText(m) {
  if (m < 1000) return (Math.round(m/10)*10) + ' Metern';
  return (m/1000).toFixed(1).replace('.', ',') + ' Kilometern';
}
function naviDistKurz(m) {
  if (m == null) return '';
  if (m < 1000) return (Math.round(m/10)*10) + ' m';
  return (m/1000).toFixed(1).replace('.', ',') + ' km';
}

async function naviRouteHolen(startLat, startLng, zielLat, zielLng, profil) {
  const osrm = _NAVI_PROFIL_OSRM[profil] || 'driving';
  try {
    const url = `https://router.project-osrm.org/route/v1/${osrm}/${startLng},${startLat};${zielLng},${zielLat}?overview=full&geometries=geojson&steps=true`;
    const res = await fetch(url, { signal: AbortSignal.timeout(15000) });
    if (!res.ok) return null;
    const data = await res.json();
    if (data.code !== 'Ok' || !data.routes?.length) return null;
    const r = data.routes[0];
    const steps = (r.legs || []).flatMap(l => l.steps || []);
    if (steps.length === 0) return null;
    return { steps, geoJson: r.geometry, distance: r.distance, duration: r.duration };
  } catch { return null; }
}

function naviAnsagen(text) {
  if (!text || state.navi?.stumm || !window.speechSynthesis) return;
  try {
    speechSynthesis.cancel();
    const u = new SpeechSynthesisUtterance(text);
    u.lang = 'de-DE'; u.rate = 1.0;
    stimmeAnwenden(u);
    speechSynthesis.speak(u);
  } catch {}
}

function naviSprecheToggle() {
  if (!state.navi) return;
  state.navi.stumm = !state.navi.stumm;
  if (state.navi.stumm && window.speechSynthesis) speechSynthesis.cancel();
  naviOverlayAktualisieren();
}

async function naviStarten(profil) {
  const m = state.routeMultiModi;
  if (!m || m.lat == null) { toast('⚠️ Bitte zuerst eine Route berechnen'); return; }
  if (!navigator.geolocation) { toast('⚠️ GPS auf diesem Gerät nicht verfügbar'); return; }
  // Sprachausgabe direkt im Tap freischalten (wichtig für iOS)
  naviAnsagen('Navigation wird gestartet');
  toast('🧭 Navigation wird gestartet…');

  navigator.geolocation.getCurrentPosition(async pos => {
    const sLat = pos.coords.latitude, sLng = pos.coords.longitude;
    const route = await naviRouteHolen(sLat, sLng, m.lat, m.lng, profil || 'auto');
    if (!route) { toast('⚠️ Route konnte nicht berechnet werden'); return; }
    state.navi = {
      aktiv: true, profil: profil || 'auto',
      ziel: { lat: m.lat, lng: m.lng, name: m.ziel },
      steps: route.steps, geoJson: route.geoJson,
      stepIndex: Math.min(1, route.steps.length - 1),
      watchId: null, posMarker: null, stumm: false,
      angesagtVorab: -1, angesagtJetzt: -1,
      offRouteZaehler: 0, rerouting: false,
      restDistanz: route.distance, restDauer: route.duration
    };
    if (state.routeSchicht) {
      state.routeSchicht.clearLayers();
      L.geoJSON(route.geoJson, { style:{ color:'#4F46E5', weight:6, opacity:.85 } }).addTo(state.routeSchicht);
    }
    if (state.karte) state.karte.setView([sLat, sLng], 16);
    naviOverlayZeigen();
    naviAnsagen(naviAnweisung(state.navi.steps[state.navi.stepIndex]));
    state.navi.watchId = navigator.geolocation.watchPosition(
      naviPositionUpdate,
      () => {},
      { enableHighAccuracy: true, maximumAge: 2000, timeout: 12000 }
    );
  }, () => {
    toast('⚠️ Standort nicht verfügbar — bitte GPS-Zugriff erlauben');
  }, { enableHighAccuracy: true, timeout: 12000 });
}

function naviAbstandZurRoute(lat, lng) {
  const coords = state.navi?.geoJson?.coordinates;
  if (!coords || !coords.length) return 0;
  let min = Infinity;
  for (let i = 0; i < coords.length; i++) {
    const d = haversine(lat, lng, coords[i][1], coords[i][0]);
    if (d < min) min = d;
  }
  return min;
}

function naviPositionUpdate(pos) {
  const n = state.navi;
  if (!n || !n.aktiv) return;
  const lat = pos.coords.latitude, lng = pos.coords.longitude;

  // Position auf der Karte anzeigen und mitführen
  if (state.karte) {
    if (!n.posMarker) {
      n.posMarker = L.circleMarker([lat, lng], { radius:9, color:'#fff', weight:3, fillColor:'#2563EB', fillOpacity:1 }).addTo(state.karte);
    } else {
      n.posMarker.setLatLng([lat, lng]);
    }
    state.karte.panTo([lat, lng], { animate: true });
  }

  // Off-Route erkennen → neu berechnen
  if (naviAbstandZurRoute(lat, lng) > 65) {
    n.offRouteZaehler++;
    if (n.offRouteZaehler >= 3 && !n.rerouting) { naviNeuberechnen(lat, lng); return; }
  } else {
    n.offRouteZaehler = 0;
  }

  const step = n.steps[n.stepIndex];
  const ml = step?.maneuver?.location;
  if (!ml) return;
  const distZ = haversine(lat, lng, ml[1], ml[0]);

  if (distZ < 22) {
    // Manöver erreicht → nächster Schritt
    if (n.stepIndex >= n.steps.length - 1) { naviZielErreicht(); return; }
    n.stepIndex++;
    n.angesagtVorab = -1; n.angesagtJetzt = -1;
    naviAnsagen(naviAnweisung(n.steps[n.stepIndex]));
  } else if (distZ < 45 && n.angesagtJetzt !== n.stepIndex) {
    n.angesagtJetzt = n.stepIndex;
    naviAnsagen('Jetzt ' + naviAnweisung(step));
  } else if (distZ < 230 && n.angesagtVorab !== n.stepIndex) {
    n.angesagtVorab = n.stepIndex;
    naviAnsagen('In ' + naviDistText(distZ) + ' ' + naviAnweisung(step));
  }

  // Restdistanz und -zeit aktualisieren
  let restD = distZ, restT = 0;
  for (let i = n.stepIndex + 1; i < n.steps.length; i++) restD += n.steps[i].distance || 0;
  for (let i = n.stepIndex; i < n.steps.length; i++) restT += n.steps[i].duration || 0;
  n.restDistanz = restD;
  n.restDauer = restT;

  naviOverlayAktualisieren(distZ);
}

async function naviNeuberechnen(lat, lng) {
  const n = state.navi;
  if (!n) return;
  n.rerouting = true;
  naviAnsagen('Die Route wird neu berechnet');
  toast('🧭 Route wird neu berechnet…');
  const route = await naviRouteHolen(lat, lng, n.ziel.lat, n.ziel.lng, n.profil);
  if (route && state.navi) {
    n.steps = route.steps;
    n.geoJson = route.geoJson;
    n.stepIndex = Math.min(1, route.steps.length - 1);
    n.angesagtVorab = -1; n.angesagtJetzt = -1;
    n.offRouteZaehler = 0;
    if (state.routeSchicht) {
      state.routeSchicht.clearLayers();
      L.geoJSON(route.geoJson, { style:{ color:'#4F46E5', weight:6, opacity:.85 } }).addTo(state.routeSchicht);
    }
    naviAnsagen(naviAnweisung(route.steps[n.stepIndex]));
    naviOverlayAktualisieren();
  }
  n.rerouting = false;
}

function naviZielErreicht() {
  naviAnsagen('Sie haben Ihr Ziel erreicht');
  toast('🏁 Ziel erreicht!');
  naviBeenden();
}

function naviBeenden() {
  const n = state.navi;
  if (n) {
    if (n.watchId != null && navigator.geolocation) { try { navigator.geolocation.clearWatch(n.watchId); } catch {} }
    if (n.posMarker && state.karte) { try { state.karte.removeLayer(n.posMarker); } catch {} }
  }
  if (window.speechSynthesis) { try { speechSynthesis.cancel(); } catch {} }
  state.navi = null;
  if (_naviOverlayEl) { _naviOverlayEl.remove(); _naviOverlayEl = null; }
}

function naviOverlayZeigen() {
  if (_naviOverlayEl) _naviOverlayEl.remove();
  _naviOverlayEl = document.createElement('div');
  _naviOverlayEl.className = 'navi-overlay';
  document.body.appendChild(_naviOverlayEl);
  naviOverlayAktualisieren();
}

function naviOverlayAktualisieren(distZ) {
  if (!_naviOverlayEl || !state.navi) return;
  const n = state.navi;
  const step = n.steps[n.stepIndex] || n.steps[n.steps.length - 1];
  const naechster = n.steps[n.stepIndex + 1];
  const distAnzeige = distZ != null ? naviDistKurz(distZ) : '';
  const restKm = naviDistKurz(n.restDistanz);
  const restMin = n.restDauer != null ? Math.max(1, Math.round(n.restDauer / 60)) + ' Min.' : '';
  _naviOverlayEl.innerHTML = `
    <div class="navi-top">
      <div class="navi-icon-gross">${naviIcon(step)}</div>
      <div class="navi-text-wrap">
        ${distAnzeige ? `<div class="navi-dist">${distAnzeige}</div>` : ''}
        <div class="navi-text">${esc(naviAnweisung(step))}</div>
        ${naechster ? `<div class="navi-danach">danach ${naviIcon(naechster)} ${esc(naviAnweisung(naechster))}</div>` : ''}
      </div>
    </div>
    <div class="navi-bottom">
      <div class="navi-stat"><span>🏁 ${esc(n.ziel.name || 'Ziel')}</span><span>${restKm}${restKm&&restMin?' · ':''}${restMin}</span></div>
      <div class="navi-bottom-btns">
        <button class="navi-btn-stumm" onclick="naviSprecheToggle()">${n.stumm ? '🔇 Ton aus' : '🔊 Ton an'}</button>
        <button class="navi-btn-beenden" onclick="naviBeenden()">✕ Navigation beenden</button>
      </div>
    </div>`;
}

// ===== Wander- & Spazierwege (live aus OpenStreetMap) =====
function _wegHaversine(lat1, lng1, lat2, lng2) {
  const R = 6371;
  const dLat = (lat2 - lat1) * Math.PI / 180;
  const dLng = (lng2 - lng1) * Math.PI / 180;
  const a = Math.sin(dLat / 2) ** 2
    + Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) * Math.sin(dLng / 2) ** 2;
  return 2 * R * Math.asin(Math.sqrt(a));
}
// Kompass-Peilung von Punkt a nach b in Grad (0 = Nord, 90 = Ost)
function _bearing(a, b) {
  const phi1 = a[0]*Math.PI/180, phi2 = b[0]*Math.PI/180;
  const dLambda = (b[1]-a[1])*Math.PI/180;
  const y = Math.sin(dLambda) * Math.cos(phi2);
  const x = Math.cos(phi1)*Math.sin(phi2) - Math.sin(phi1)*Math.cos(phi2)*Math.cos(dLambda);
  return (Math.atan2(y, x) * 180/Math.PI + 360) % 360;
}

// Abbiegepunkte eines Weges aus der Geometrie ableiten: vergleicht die
// Geh-Richtung ~22 m vor und nach jedem Punkt — ab 40° Änderung = Kurve.
// So entstehen aus der reinen Linie echte "links/rechts abbiegen"-Hinweise.
function _wegTurnsBerechnen(punkte, kum) {
  const turns = [];
  const N = punkte.length;
  if (N < 3) return turns;
  const W = 22;
  for (let i = 1; i < N - 1; i++) {
    if (kum[i] - kum[i-1] > 200 || kum[i+1] - kum[i] > 200) continue; // Segment-Sprung überspringen
    let j = i; while (j > 0 && kum[i] - kum[j] < W) j--;
    let k = i; while (k < N - 1 && kum[k] - kum[i] < W) k++;
    if (j === i || k === i) continue;
    const bIn  = _bearing(punkte[j], punkte[i]);
    const bOut = _bearing(punkte[i], punkte[k]);
    const d = ((bOut - bIn + 540) % 360) - 180;
    if (Math.abs(d) < 40) continue;
    const last = turns[turns.length - 1];
    if (last && kum[i] - last.kum < 30) {  // nahe Kurven zusammenfassen
      if (Math.abs(d) > Math.abs(last.delta))
        Object.assign(last, { idx:i, kum:kum[i], delta:d, dir: d>0?'rechts':'links', scharf: Math.abs(d)>=105 });
      continue;
    }
    turns.push({ idx:i, kum:kum[i], delta:d, dir: d>0?'rechts':'links', scharf: Math.abs(d)>=105 });
  }
  return turns;
}

function gespeicherteWanderwege() {
  try { return JSON.parse(localStorage.getItem('familienapp_wanderwege') || '[]'); }
  catch { return []; }
}
function _wanderwegeSpeichernListe(arr) {
  try { localStorage.setItem('familienapp_wanderwege', JSON.stringify(arr.slice(0, 50))); } catch {}
}
function wanderwegSpeichern(w) {
  if (!w || !w.id) return;
  const liste = gespeicherteWanderwege();
  if (liste.some(x => x.id === w.id)) { toast('💾 Bereits gespeichert.'); return; }
  liste.unshift({ id: w.id, name: w.name, lat: w.lat, lng: w.lng, typ: w.typ });
  _wanderwegeSpeichernListe(liste);
  toast('💾 Weg gespeichert');
  render();
}
function wanderwegSpeichernIdx(i) {
  const w = (state.wanderwegeListe || [])[i];
  if (w) wanderwegSpeichern(w);
}
function wanderwegLoeschen(id) {
  _wanderwegeSpeichernListe(gespeicherteWanderwege().filter(w => w.id !== id));
  render();
}
async function wanderwegeStandortSuchen() {
  const inp = el('ww-standort-input');
  const q = inp?.value.trim();
  if (!q) return;
  inp.disabled = true;
  try {
    const url = /^\d{5}$/.test(q)
      ? `https://nominatim.openstreetmap.org/search?postalcode=${q}&country=de&format=json&limit=1`
      : `https://nominatim.openstreetmap.org/search?q=${encodeURIComponent(q)}&format=json&limit=1&accept-language=de`;
    const res = await fetch(url);
    const d = await res.json();
    if (!d.length) { toast('⚠️ Ort nicht gefunden'); inp.disabled = false; return; }
    state.umgebungStandort = { lat: parseFloat(d[0].lat), lng: parseFloat(d[0].lon), name: q };
    state.wanderwegeListe = null;
    render();
  } catch {
    toast('⚠️ Suche fehlgeschlagen');
    if (inp) inp.disabled = false;
  }
}
async function wanderwegeLaden() {
  const s = state.umgebungStandort;
  if (!s) { toast('⚠️ Bitte zuerst einen Standort eingeben.'); return; }
  state.wanderwegeLaden = true;
  state.wanderwegeListe = null;
  render();
  const radius = state.wanderwegeRadius || 8000;
  const query = `[out:json][timeout:25];
(
  relation["route"~"hiking|foot|walking"]["name"](around:${radius},${s.lat},${s.lng});
  way["highway"~"path|footway"]["name"](around:${radius},${s.lat},${s.lng});
);
out tags center 80;`;
  try {
    const res = await fetch('https://overpass-api.de/api/interpreter', {
      method: 'POST',
      headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
      body: 'data=' + encodeURIComponent(query),
      signal: AbortSignal.timeout(30000)
    });
    if (!res.ok) throw new Error('Overpass ' + res.status);
    const d = await res.json();
    const liste = (d.elements || []).map(e => {
      const lat = e.lat ?? e.center?.lat;
      const lng = e.lon ?? e.center?.lon;
      if (lat == null || lng == null) return null;
      const name = e.tags?.name;
      if (!name) return null;
      const r = e.tags?.route;
      const typ = r === 'hiking' ? '🥾 Wanderweg'
        : (r === 'foot' || r === 'walking') ? '🚶 Spazierweg'
        : '🚶 Weg';
      return {
        id: e.type + '/' + e.id,
        name, lat, lng, typ,
        distKm: _wegHaversine(s.lat, s.lng, lat, lng)
      };
    }).filter(Boolean);
    // Doppelte Namen entfernen, nach Distanz sortieren, auf 60 begrenzen
    const gesehen = new Set();
    state.wanderwegeListe = liste
      .filter(w => { const k = w.name.toLowerCase(); if (gesehen.has(k)) return false; gesehen.add(k); return true; })
      .sort((a, b) => a.distKm - b.distKm)
      .slice(0, 60);
  } catch (e) {
    state.wanderwegeListe = [];
    toast('⚠️ Wege konnten nicht geladen werden.');
  }
  state.wanderwegeLaden = false;
  render();
}
function renderWanderwege() {
  const s = state.umgebungStandort;
  const liste = state.wanderwegeListe;
  const laden = state.wanderwegeLaden;
  const gespeichert = gespeicherteWanderwege();
  const radius = state.wanderwegeRadius || 8000;
  return `
  <div class="section-title">🥾 Wander- & Spazierwege</div>
  <p class="section-sub">Echte Wege aus OpenStreetMap in Ihrer Umgebung — finden, anschauen und speichern. Ideal für gemütliche Spaziergänge und Wanderungen.</p>

  <div class="standort-box">
    <div style="display:flex;gap:.5rem;align-items:center;flex-wrap:wrap">
      <input id="ww-standort-input" class="standort-input" type="text"
        placeholder="PLZ, Stadt oder Adresse"
        value="${esc(s?.name || '')}"
        onkeydown="if(event.key==='Enter')wanderwegeStandortSuchen()" />
      <button class="btn btn-primary" onclick="wanderwegeStandortSuchen()">🔍 Suchen</button>
      <button class="btn btn-outline gps-btn" onclick="gpsStandort()">📡 GPS</button>
    </div>
    ${s ? `<div style="margin-top:.5rem;font-size:.82rem;color:var(--g700)">📍 <strong>${esc(s.name)}</strong> · Radius:
      <select onchange="state.wanderwegeRadius=parseInt(this.value);render()" style="margin-left:.3rem;padding:.2rem .35rem;border-radius:.4rem;border:1px solid var(--g200)">
        ${[2000,5000,8000,15000,25000].map(r => `<option value="${r}" ${radius===r?'selected':''}>${r/1000} km</option>`).join('')}
      </select>
      <button class="btn btn-primary" style="margin-top:.6rem;width:100%" onclick="wanderwegeLaden()" ${laden?'disabled':''}>
        ${laden ? '⏳ Suche läuft…' : '🥾 Wege in der Nähe suchen'}
      </button>
    </div>` : `<div style="margin-top:.5rem;font-size:.82rem;color:var(--g500)">Bitte zuerst einen Standort eingeben.</div>`}
  </div>

  ${(liste && liste.length) || gespeichert.length ? `
  <div id="ww-karte" style="height:380px;border-radius:20px;margin-top:1rem;border:1px solid var(--g200);box-shadow:var(--s2);z-index:1"></div>
  <div style="font-size:.74rem;color:var(--g500);margin-top:.4rem;text-align:center">💡 Tippe einen Weg unten an, um ihn auf der Karte zu zeigen</div>` : ''}

  ${gespeichert.length ? `
  <div class="block-title" style="margin-top:1.25rem">💾 Gespeicherte Wege (${gespeichert.length})</div>
  <div class="ww-grid">
    ${gespeichert.map(w => `
    <div class="ww-karte">
      <div class="ww-karte-titel">${esc(w.typ || '🚶 Weg')}</div>
      <div class="ww-karte-name">${esc(w.name)}</div>
      <div class="ww-karte-aktionen">
        <button class="btn btn-primary btn-sm" onclick="wanderwegGehen('${esc(w.id)}','${esc((w.name||'').replace(/'/g,''))}')">🥾 Weg gehen</button>
        <button class="btn btn-outline btn-sm" onclick="wanderwegLoeschen('${esc(w.id)}')">✕ Entfernen</button>
      </div>
    </div>`).join('')}
  </div>` : ''}

  ${liste == null ? '' : !liste.length ? `
  <div class="info-box orange" style="margin-top:1rem"><span class="ib-icon">😕</span><div class="ib-text"><strong>Keine Wege gefunden.</strong> Radius vergrößern oder anderen Standort wählen.</div></div>
  ` : `
  <div class="block-title" style="margin-top:1.25rem">📍 Wege in der Nähe (${liste.length})</div>
  <div class="ww-grid">
    ${liste.map((w, i) => `
    <div class="ww-karte">
      <div class="ww-karte-titel">${esc(w.typ)} · ${w.distKm.toFixed(1)} km</div>
      <div class="ww-karte-name">${esc(w.name)}</div>
      <div class="ww-karte-aktionen">
        <button class="btn btn-primary btn-sm" onclick="wanderwegGehen('${esc(w.id)}','${esc((w.name||'').replace(/'/g,''))}')">🥾 Weg gehen</button>
        <button class="btn btn-outline btn-sm" onclick="wanderwegSpeichernIdx(${i})">💾 Speichern</button>
      </div>
    </div>`).join('')}
  </div>`}`;
}

// Leaflet-Karte für die Wanderwege-Sektion aufbauen
function initWanderwegeKarte() {
  const mapEl = el('ww-karte');
  if (!mapEl || typeof L === 'undefined') return;
  const s = state.umgebungStandort;
  const liste = state.wanderwegeListe || [];
  const gespeichert = (typeof gespeicherteWanderwege === 'function') ? gespeicherteWanderwege() : [];
  if (!s && !liste.length && !gespeichert.length) return;

  if (state.wwKarte) { state.wwKarte.remove(); state.wwKarte = null; }
  const center = s ? [s.lat, s.lng] : (liste[0] ? [liste[0].lat, liste[0].lng] : [51.16, 10.45]);
  const karte = L.map('ww-karte').setView(center, 12);
  state.wwKarte = karte;
  L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
    attribution: '© <a href="https://www.openstreetmap.org/">OpenStreetMap</a>', maxZoom: 19
  }).addTo(karte);

  const punkte = [];
  if (s) {
    const ich = L.divIcon({ html:'<div style="background:#2563EB;width:16px;height:16px;border-radius:50%;border:3px solid white;box-shadow:0 2px 8px rgba(37,99,235,.6)"></div>', iconSize:[16,16], iconAnchor:[8,8], className:'' });
    L.marker([s.lat, s.lng], { icon: ich }).addTo(karte).bindPopup('<strong>📍 Ihr Standort</strong>');
    punkte.push([s.lat, s.lng]);
  }
  const wegIcon = (farbe) => L.divIcon({ html:`<div style="background:${farbe};width:13px;height:13px;border-radius:50%;border:2.5px solid white;box-shadow:0 1px 5px rgba(0,0,0,.4)"></div>`, iconSize:[13,13], iconAnchor:[6,6], className:'' });
  liste.forEach(w => {
    L.marker([w.lat, w.lng], { icon: wegIcon('#059669') }).addTo(karte)
      .bindPopup(`<strong>${esc(w.typ || '🚶 Weg')}</strong><br>${esc(w.name)}<br>${w.distKm != null ? w.distKm.toFixed(1) + ' km entfernt' : ''}`);
    punkte.push([w.lat, w.lng]);
  });
  gespeichert.forEach(w => {
    L.marker([w.lat, w.lng], { icon: wegIcon('#D97706') }).addTo(karte)
      .bindPopup(`<strong>💾 ${esc(w.name)}</strong><br>Gespeicherter Weg`);
    punkte.push([w.lat, w.lng]);
  });
  if (punkte.length > 1) {
    karte.fitBounds(punkte, { padding: [40, 40], maxZoom: 14 });
  }
}

// Einen Weg auf der Wanderwege-Karte anzeigen (nur Punkt)
function wanderwegAufKarte(lat, lng, name) {
  const mapEl = el('ww-karte');
  if (!mapEl) { toast('⚠️ Karte nicht verfügbar'); return; }
  mapEl.scrollIntoView({ behavior: 'smooth', block: 'center' });
  if (!state.wwKarte) initWanderwegeKarte();
  if (state.wwKarte) {
    state.wwKarte.flyTo([lat, lng], 15, { duration: .8 });
    L.popup().setLatLng([lat, lng]).setContent(`<strong>${esc(name || 'Weg')}</strong>`).openOn(state.wwKarte);
  }
}

// GPS-Watch-ID für die Geh-Navigation
let _wwGpsWatch = null;

// Einen Weg "gehbar" öffnen: kompletten Verlauf laden, als Linie zeichnen + GPS-Navigation
async function wanderwegGehen(id, name) {
  const mapEl = el('ww-karte');
  if (!mapEl) { toast('⚠️ Karte nicht verfügbar'); return; }
  if (!state.wwKarte) initWanderwegeKarte();
  if (!state.wwKarte) { toast('⚠️ Karte ist noch nicht bereit'); return; }
  mapEl.scrollIntoView({ behavior: 'smooth', block: 'center' });
  toast('🗺️ Wegverlauf wird geladen …');

  const [typ, osmId] = String(id).split('/');
  const sel = typ === 'relation' ? `relation(${osmId})` : `way(${osmId})`;
  const query = `[out:json][timeout:25];${sel};out geom;`;
  try {
    const res = await fetch('https://overpass-api.de/api/interpreter', {
      method: 'POST',
      headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
      body: 'data=' + encodeURIComponent(query),
      signal: AbortSignal.timeout(25000)
    });
    if (!res.ok) throw new Error('Overpass ' + res.status);
    const d = await res.json();
    // Wegverlauf als Liniensegmente extrahieren
    const segmente = [];
    (d.elements || []).forEach(e => {
      if (e.type === 'way' && Array.isArray(e.geometry)) {
        segmente.push(e.geometry.map(g => [g.lat, g.lon]));
      } else if (e.type === 'relation' && Array.isArray(e.members)) {
        e.members.forEach(m => {
          if (Array.isArray(m.geometry)) segmente.push(m.geometry.map(g => [g.lat, g.lon]));
        });
      }
    });
    const valide = segmente.filter(s => s.length > 1);
    if (!valide.length) { toast('⚠️ Wegverlauf nicht verfügbar — zeige nur den Startpunkt'); return; }

    // Alte Weg-Linie entfernen, neue zeichnen
    if (state.wwWegLinie) { try { state.wwKarte.removeLayer(state.wwWegLinie); } catch {} }
    state.wwWegLinie = L.layerGroup(
      valide.map(seg => L.polyline(seg, { color: '#059669', weight: 6, opacity: .9 }))
    ).addTo(state.wwKarte);
    state.wwKarte.fitBounds(valide.flat(), { padding: [45, 45] });

    // Wegverlauf für die Navigation merken: flache Punktliste + kumulative Länge,
    // damit der GPS-Callback Distanz zum Weg und groben Fortschritt berechnen kann.
    const flach = valide.flat();
    const kum = [0];
    for (let i = 1; i < flach.length; i++) {
      kum[i] = kum[i - 1] + haversine(flach[i-1][0], flach[i-1][1], flach[i][0], flach[i][1]);
    }
    state.wwWegPunkte = flach;
    state.wwWegKum = kum;
    state.wwWegGesamtM = kum[kum.length - 1] || 0;
    state.wwWegTurns = _wegTurnsBerechnen(flach, kum);   // Abbiegepunkte für Turn-by-Turn
    state.wwWegRichtung = null;                          // Geh-Richtung: erster GPS-Fix legt sie fest

    // Geh-Navigation starten — Live-Standort
    wanderwegNaviStarten(name);
    toast('🥾 Folge der grünen Linie — dein Standort wird live angezeigt');
  } catch (e) {
    toast('⚠️ Wegverlauf konnte nicht geladen werden');
  }
}

// Fixiertes Navi-Banner am unteren Rand — überlebt render(), da direkt am body
function wanderwegNaviBanner() {
  let b = document.getElementById('ww-navi-banner');
  if (!b) {
    b = document.createElement('div');
    b.id = 'ww-navi-banner';
    b.className = 'ww-navi-banner';
    document.body.appendChild(b);
  }
  return b;
}

// Live-GPS-Navigation auf der Wanderwege-Karte: Turn-by-Turn-Hinweise.
// Alle Berechnungen sind lokal (GPS + Weg-Geometrie) — funktioniert offline.
function wanderwegNaviStarten(wegName) {
  if (!navigator.geolocation || !state.wwKarte) { return; }
  wanderwegNaviStoppen();
  const banner = wanderwegNaviBanner();
  banner.innerHTML = `
    <div class="ww-navi-info">
      <div class="ww-navi-status" id="ww-navi-status">📡 Standort wird gesucht…</div>
      <div class="ww-navi-detail" id="ww-navi-detail">🥾 ${esc(wegName || 'Weg')}</div>
    </div>
    <button class="ww-navi-stop" onclick="wanderwegNaviStoppen()">✕ Beenden</button>`;
  banner.style.display = 'flex';

  _wwGpsWatch = navigator.geolocation.watchPosition(
    pos => {
      if (!state.wwKarte) return;
      const lat = pos.coords.latitude, lng = pos.coords.longitude;
      const ll = [lat, lng];
      if (state.wwGpsMarker) {
        state.wwGpsMarker.setLatLng(ll);
      } else {
        const ich = L.divIcon({
          html: '<div style="background:#2563EB;width:18px;height:18px;border-radius:50%;border:4px solid white;box-shadow:0 0 0 5px rgba(37,99,235,.35)"></div>',
          iconSize: [18, 18], iconAnchor: [9, 9], className: ''
        });
        state.wwGpsMarker = L.marker(ll, { icon: ich, zIndexOffset: 1000 }).addTo(state.wwKarte);
        state.wwGpsMarker.bindPopup('<strong>📍 Hier bist du</strong>');
        state.wwKarte.panTo(ll);
      }
      const st = el('ww-navi-status'), det = el('ww-navi-detail');
      if (!st) return;
      const punkte = state.wwWegPunkte, kum = state.wwWegKum, gesamt = state.wwWegGesamtM || 0;
      if (!punkte || !punkte.length) { st.textContent = '📍 Standort wird verfolgt'; return; }

      // Nächstgelegenen Wegpunkt finden
      let minDist = Infinity, minIdx = 0;
      for (let i = 0; i < punkte.length; i++) {
        const dM = haversine(lat, lng, punkte[i][0], punkte[i][1]);
        if (dM < minDist) { minDist = dM; minIdx = i; }
      }
      // Geh-Richtung beim ersten Fix festlegen — zum weiter entfernten Wegende
      if (state.wwWegRichtung == null) {
        const dStart = haversine(lat, lng, punkte[0][0], punkte[0][1]);
        const dEnd   = haversine(lat, lng, punkte[punkte.length-1][0], punkte[punkte.length-1][1]);
        state.wwWegRichtung = dStart <= dEnd ? 1 : -1;
      }
      const ri = state.wwWegRichtung;
      const userKum = kum[minIdx];
      const fmt = m => m < 1000 ? Math.max(0, Math.round(m/10)*10) + ' m'
                                : (m/1000).toFixed(1).replace('.', ',') + ' km';
      st.classList.remove('ww-navi-ok', 'ww-navi-warn');

      // Nicht auf dem Weg → erst zurück zur Linie führen
      if (minDist > 75) {
        st.textContent = `⚠️ ${fmt(minDist)} vom Weg entfernt`;
        st.classList.add('ww-navi-warn');
        if (det) det.textContent = 'Zurück zur grünen Linie gehen';
        return;
      }
      if (minDist > 25) {
        st.textContent = `↗️ Noch ${fmt(minDist)} bis zum Weg`;
        if (det) det.textContent = 'Geh Richtung grüne Linie';
        return;
      }

      // Auf dem Weg → Turn-by-Turn
      const restZiel = ri === 1 ? Math.max(0, gesamt - userKum) : userKum;
      const turns = state.wwWegTurns || [];
      let next = null;
      if (ri === 1) { for (const t of turns) if (t.kum > userKum + 8) { next = t; break; } }
      else { for (let x = turns.length-1; x >= 0; x--) if (turns[x].kum < userKum - 8) { next = turns[x]; break; } }

      if (restZiel <= 20) {
        st.textContent = '🏁 Ziel erreicht — schöne Wanderung!';
        st.classList.add('ww-navi-ok');
      } else if (next) {
        const distT = Math.abs(next.kum - userKum);
        let dir = next.dir;
        if (ri === -1) dir = dir === 'rechts' ? 'links' : 'rechts';
        const pfeil = dir === 'rechts' ? '➡️' : '⬅️';
        const wort = next.scharf ? 'scharf ' + dir : dir;
        if (distT <= 15) { st.textContent = `${pfeil} Jetzt ${wort} abbiegen`; st.classList.add('ww-navi-ok'); }
        else if (distT <= 400) { st.textContent = `${pfeil} Noch ${fmt(distT)}, dann ${wort}`; }
        else { st.textContent = '✅ Geradeaus dem Weg folgen'; st.classList.add('ww-navi-ok'); }
      } else {
        st.textContent = '✅ Geradeaus dem Weg folgen';
        st.classList.add('ww-navi-ok');
      }
      const proz = gesamt > 0 ? Math.min(100, Math.max(0, Math.round((gesamt - restZiel) / gesamt * 100))) : 0;
      if (det) det.textContent = `🏁 Noch ${fmt(restZiel)} bis zum Ziel · ${proz}% geschafft`;
    },
    () => {
      const st = el('ww-navi-status');
      if (st) { st.textContent = '⚠️ Standort nicht verfügbar — GPS/Ortung erlauben'; st.classList.add('ww-navi-warn'); }
      toast('⚠️ Standort nicht verfügbar — bitte GPS/Ortung erlauben');
    },
    { enableHighAccuracy: true, maximumAge: 5000, timeout: 15000 }
  );
}

// Geh-Navigation beenden — GPS-Watch stoppen, Live-Marker + Banner entfernen
function wanderwegNaviStoppen() {
  if (_wwGpsWatch != null && navigator.geolocation) {
    navigator.geolocation.clearWatch(_wwGpsWatch);
  }
  _wwGpsWatch = null;
  if (state.wwGpsMarker && state.wwKarte) {
    try { state.wwKarte.removeLayer(state.wwGpsMarker); } catch {}
  }
  state.wwGpsMarker = null;
  const b = document.getElementById('ww-navi-banner');
  if (b) b.remove();
}

// ===== Routenplaner (eigene Sektion) =====
function renderRoutenplaner() {
  const user = getUser() || {};
  const start = state.routenplanerStart || state.umgebungStandort?.name || user.ort || '';
  const ziel  = state.routeZiel || '';
  const ziele = zieleLaden();
  const ergebnis = state.routeMultiModi;

  return `
  <div class="umg-hero" style="background:linear-gradient(140deg,#4F46E5 0%,#7C3AED 55%,#EC4899 100%);box-shadow:0 10px 30px rgba(124,58,237,.28)">
    <div class="umg-hero-tag">🗺️ Routenplaner</div>
    <div class="umg-hero-name">Wohin geht die Reise?</div>
    <div class="umg-hero-sub">Plane Routen mit Auto, Fahrrad und zu Fuß — Ziele werden für später gespeichert</div>
    <div class="hero-chips">
      <span class="chip">📍 Start: ${esc(start || 'noch nicht gesetzt')}</span>
      ${ziel ? `<span class="chip">🎯 ${esc(ziel)}</span>` : ''}
      ${ziele.length ? `<span class="chip">💾 ${ziele.length} gespeichert</span>` : ''}
    </div>
  </div>

  <div class="standort-box">
    <div style="font-weight:700;font-size:.95rem;margin-bottom:.75rem">📍 Start &amp; Ziel</div>
    <div style="display:flex;flex-direction:column;gap:.55rem">
      <input id="rp-start" class="standort-input" type="text"
        placeholder="Startadresse oder PLZ (leer = aktueller Standort)"
        value="${esc(start)}" autocomplete="off" />
      <input id="rp-ziel" class="standort-input" type="text"
        placeholder="Zieladresse (z. B. Hamburg Hauptbahnhof)"
        value="${esc(ziel)}" autocomplete="off"
        onkeydown="if(event.key==='Enter')routenplanerBerechnen()" />
    </div>
    <div style="display:flex;gap:.5rem;flex-wrap:wrap;margin-top:.7rem">
      <button class="btn btn-primary" style="flex:1" onclick="routenplanerBerechnen()" ${state.routeLaden?'disabled':''}>
        ${state.routeLaden ? '⏳ Berechne…' : '🗺️ Route berechnen'}
      </button>
      ${ergebnis && !ergebnis.laden ? `<button class="btn btn-outline" onclick="routenplanerZielSpeichern()">💾 Ziel speichern</button>` : ''}
      ${ergebnis ? `<button class="btn btn-outline" onclick="routeZurücksetzen();render()">✕ Schließen</button>` : ''}
    </div>
    <div id="rp-fehler" style="display:none;margin-top:.6rem;padding:.5rem .75rem;background:#FEE2E2;color:#DC2626;border-radius:.5rem;font-size:.82rem;font-weight:600"></div>
  </div>

  <div id="rp-karte" style="height:400px;border-radius:20px;margin-bottom:1rem;border:1px solid var(--g200);box-shadow:var(--s2);z-index:1"></div>

  ${ergebnis ? `<div style="margin-bottom:1rem">${renderMultiRoute({ name: start })}</div>` : ''}

  ${ziele.length ? `
  <div class="block-title" style="margin-top:1rem">💾 Gespeicherte Ziele (${ziele.length})</div>
  <div class="rp-ziele-grid">
    ${ziele.map(z => `
    <div class="rp-ziel-karte">
      <div class="rp-ziel-name">📍 ${esc(z.name)}</div>
      <div class="rp-ziel-aktionen">
        <button class="btn btn-primary btn-sm" onclick="routenplanerZielAufrufen('${esc(z.id)}')">🗺️ Route hierhin</button>
        <button class="btn btn-outline btn-sm" onclick="routenplanerZielLoeschen('${esc(z.id)}')">✕ Entfernen</button>
      </div>
    </div>`).join('')}
  </div>` : `
  <div class="info-box blau" style="margin-top:1rem">
    <span class="ib-icon">💡</span>
    <div class="ib-text"><strong>Tipp:</strong> Nach jeder berechneten Route kannst du das Ziel speichern. So sind häufige Adressen (Schule, Arbeit, Oma) mit einem Klick wieder abrufbar.</div>
  </div>`}`;
}

// Leaflet-Karte für den Routenplaner — zeigt Start, Ziel und die Route
function initRoutenplanerKarte() {
  const mapEl = el('rp-karte');
  if (!mapEl || typeof L === 'undefined') return;

  if (state.karte) { try { state.karte.remove(); } catch {} state.karte = null; }
  const s = state.umgebungStandort;
  const center = s ? [s.lat, s.lng] : [51.16, 10.45];
  const karte = L.map('rp-karte').setView(center, s ? 12 : 6);
  state.karte = karte;
  L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
    attribution: '© <a href="https://www.openstreetmap.org/">OpenStreetMap</a>', maxZoom: 19
  }).addTo(karte);
  state.routeSchicht = L.layerGroup().addTo(karte);

  const punkte = [];
  if (s) {
    const ich = L.divIcon({ html:'<div style="background:#16A34A;width:16px;height:16px;border-radius:50%;border:3px solid white;box-shadow:0 2px 8px rgba(22,163,74,.6)"></div>', iconSize:[16,16], iconAnchor:[8,8], className:'' });
    L.marker([s.lat, s.lng], { icon: ich }).addTo(state.routeSchicht).bindPopup('<strong>🟢 Start: ' + esc(s.name || 'Standort') + '</strong>');
    punkte.push([s.lat, s.lng]);
  }
  const m = state.routeMultiModi;
  if (m && !m.laden && m.ergebnisse) {
    const aktiv = state.routeAktivProfil || 'auto';
    const erg = m.ergebnisse[aktiv] || m.ergebnisse.auto || Object.values(m.ergebnisse)[0];
    if (m.lat != null) {
      const zielIcon = L.divIcon({ html:'<div style="background:#DC2626;width:16px;height:16px;border-radius:50%;border:3px solid white;box-shadow:0 2px 8px rgba(220,38,38,.6)"></div>', iconSize:[16,16], iconAnchor:[8,8], className:'' });
      L.marker([m.lat, m.lng], { icon: zielIcon }).addTo(state.routeSchicht).bindPopup('<strong>🔴 Ziel: ' + esc(m.ziel || '') + '</strong>');
      punkte.push([m.lat, m.lng]);
    }
    if (erg && erg.geoJson) {
      const layer = L.geoJSON(erg.geoJson, { style: { color: erg.farbe || '#4F46E5', weight: 5, opacity: .85 } }).addTo(state.routeSchicht);
      try { karte.fitBounds(layer.getBounds(), { padding: [40, 40] }); return; } catch {}
    }
  }
  if (punkte.length > 1) karte.fitBounds(punkte, { padding: [50, 50] });
}

// Robuste Adress-Suche — versucht Nominatim mit mehreren Varianten,
// danach Photon als Fallback (toleranter bei ungenauen Eingaben).
async function geocodeRobust(eingabe) {
  const q = (eingabe || '').trim();
  if (!q) return null;

  const nominatim = async (suche) => {
    try {
      const res = await fetch('https://nominatim.openstreetmap.org/search?q='
        + encodeURIComponent(suche) + '&format=json&limit=5&accept-language=de',
        { signal: AbortSignal.timeout(12000) });
      if (!res.ok) return null;
      const d = await res.json();
      if (!d.length) return null;
      // Treffer mit höchster importance bevorzugen
      const best = d.sort((a, b) => (b.importance || 0) - (a.importance || 0))[0];
      return { lat: parseFloat(best.lat), lng: parseFloat(best.lon), name: best.display_name || suche };
    } catch { return null; }
  };
  const photon = async (suche) => {
    try {
      const res = await fetch('https://photon.komoot.io/api/?lang=de&limit=5&q='
        + encodeURIComponent(suche), { signal: AbortSignal.timeout(12000) });
      if (!res.ok) return null;
      const d = await res.json();
      const f = (d.features || [])[0];
      if (!f || !f.geometry) return null;
      const [lng, lat] = f.geometry.coordinates;
      const p = f.properties || {};
      const name = [p.name, p.street, p.city || p.town || p.village, p.country].filter(Boolean).join(', ');
      return { lat, lng, name: name || suche };
    } catch { return null; }
  };

  // 1) Eingabe direkt  2) mit ", Deutschland"  3) Photon-Fallback
  return (await nominatim(q))
      || (!/deutschland|germany/i.test(q) ? await nominatim(q + ', Deutschland') : null)
      || (await photon(q));
}

async function routenplanerBerechnen() {
  const startEl = el('rp-start');
  const zielEl  = el('rp-ziel');
  const fehlerEl = el('rp-fehler');
  const fehlerZeigen = (txt) => { if (fehlerEl) { fehlerEl.textContent = txt; fehlerEl.style.display = 'block'; } };
  if (fehlerEl) fehlerEl.style.display = 'none';

  const zielText = zielEl?.value.trim() || '';
  if (!zielText) { fehlerZeigen('Bitte ein Ziel eingeben.'); return; }
  state.routeZiel = zielText;
  state.routenplanerStart = startEl?.value.trim() || '';

  state.routeLaden = true;
  state.routeMultiModi = { laden: true, ergebnisse: null, ziel: zielText };
  render();

  try {
    // Start bestimmen — entweder Eingabe geocodieren oder aktuellen Standort nutzen
    let startLat, startLng, startName;
    if (state.routenplanerStart) {
      const sTreffer = await geocodeRobust(state.routenplanerStart);
      if (!sTreffer) throw new Error('Startadresse nicht gefunden. Tipp: PLZ + Stadt angeben, z. B. „10115 Berlin".');
      startLat = sTreffer.lat; startLng = sTreffer.lng;
      startName = state.routenplanerStart;
    } else if (state.umgebungStandort) {
      startLat = state.umgebungStandort.lat; startLng = state.umgebungStandort.lng;
      startName = state.umgebungStandort.name;
    } else {
      throw new Error('Kein Startpunkt — bitte oben eine Startadresse eingeben.');
    }
    // umgebungStandort temporär setzen, damit routeMultiBerechnen() es nutzen kann
    state.umgebungStandort = { name: startName, lat: startLat, lng: startLng };

    // Ziel geocodieren — robust über mehrere Anbieter
    const zTreffer = await geocodeRobust(zielText);
    if (!zTreffer) throw new Error('Ziel nicht gefunden. Tipp: genauer angeben — z. B. „Straße + Stadt" oder „PLZ + Stadt".');
    const zLat = zTreffer.lat, zLng = zTreffer.lng;
    state.routeZielKoord = { lat: zLat, lng: zLng };

    await routeMultiBerechnen(zLat, zLng, zielText);
  } catch (e) {
    // Bei Fehler: alte Route verwerfen, neu rendern, DANN Fehler auf das frische
    // Element setzen — sonst überschreibt render() die Meldung sofort wieder.
    state.routeLaden = false;
    state.routeMultiModi = null;
    render();
    const fe = el('rp-fehler');
    if (fe) { fe.textContent = e.message || 'Route konnte nicht berechnet werden.'; fe.style.display = 'block'; }
  }
}

function routenplanerZielSpeichern() {
  const name = (state.routeZiel || '').trim();
  const k = state.routeZielKoord;
  if (!name || !k) { toast('⚠️ Erst eine Route berechnen, dann speichern.'); return; }
  const liste = zieleLaden();
  if (liste.some(z => z.name.toLowerCase() === name.toLowerCase())) {
    toast('💾 Ziel ist bereits gespeichert.');
    return;
  }
  liste.unshift({ id: Date.now().toString(36), name, lat: k.lat, lng: k.lng });
  zieleSpeichern(liste);
  toast('💾 Ziel gespeichert');
  render();
}

function routenplanerZielLoeschen(id) {
  zieleSpeichern(zieleLaden().filter(z => z.id !== id));
  toast('🗑️ Ziel entfernt');
  render();
}

function routenplanerZielAufrufen(id) {
  const z = zieleLaden().find(x => x.id === id);
  if (!z) return;
  state.routeZiel = z.name;
  state.routeZielKoord = { lat: z.lat, lng: z.lng };
  // Eingabefeld direkt setzen, damit der User die Eingabe sieht
  const zielEl = el('rp-ziel'); if (zielEl) zielEl.value = z.name;
  routenplanerBerechnen();
}

// ===== Gespeicherte Ziele =====
function zieleLaden() {
  try { return JSON.parse(localStorage.getItem('familienapp_ziele') || '[]'); }
  catch { return []; }
}
function zieleSpeichern(arr) {
  try { localStorage.setItem('familienapp_ziele', JSON.stringify(arr.slice(0, 30))); } catch {}
}
function zielSpeichern() {
  const name = (state.routeZiel || '').trim();
  const k = state.routeZielKoord;
  if (!name || !k) { toast('⚠️ Erst eine Route berechnen, dann speichern.'); return; }
  const liste = zieleLaden();
  if (liste.some(z => z.name.toLowerCase() === name.toLowerCase())) {
    toast('💾 Ziel ist bereits gespeichert.');
    return;
  }
  liste.unshift({ id: Date.now().toString(36), name, lat: k.lat, lng: k.lng });
  zieleSpeichern(liste);
  toast('💾 Ziel gespeichert');
  render();
}
function zielLoeschen(id) {
  zieleSpeichern(zieleLaden().filter(z => z.id !== id));
  render();
}
function zielAufrufen(id) {
  const z = zieleLaden().find(x => x.id === id);
  if (!z) return;
  state.routeZiel = z.name;
  state.routeZielKoord = { lat: z.lat, lng: z.lng };
  const inp = el('route-ziel');
  if (inp) inp.value = z.name;
  routeBerechnen();
}

async function routeBerechnen() {
  const startEl = el('route-start');
  const zielEl  = el('route-ziel');
  const fehlerEl = el('route-fehler');
  const fehlerZeigen = (txt) => { if (fehlerEl) { fehlerEl.textContent = txt; fehlerEl.style.display = 'block'; } };
  if (!zielEl || !zielEl.value.trim()) {
    fehlerZeigen('Bitte Zieladresse eingeben.');
    return;
  }
  if (fehlerEl) fehlerEl.style.display = 'none';
  state.routeZiel = zielEl.value.trim();
  const startName = startEl?.value.trim() || state.umgebungStandort?.name || '';
  if (!state.umgebungStandort && !startName) {
    fehlerZeigen('Bitte oben einen Standort eingeben oder den Start ausfüllen.');
    return;
  }

  state.routeLaden = true;
  const btn = document.querySelector('[onclick="routeBerechnen()"]');
  if (btn) btn.textContent = '⏳ Berechne...';

  try {
    // Ziel geocodieren — weltweit, damit auch Urlaubs-Adressen funktionieren
    const geoRes = await fetch(
      `https://nominatim.openstreetmap.org/search?q=${encodeURIComponent(state.routeZiel)}&format=json&limit=1`
    );
    const geoData = await geoRes.json();
    if (!geoData.length) throw new Error('Ziel nicht gefunden — bitte Adresse prüfen (z. B. Stadt + Straße angeben).');
    const zielLat = parseFloat(geoData[0].lat), zielLng = parseFloat(geoData[0].lon);
    state.routeZielKoord = { lat: zielLat, lng: zielLng };

    // Start bestimmen
    let startLat, startLng;
    if (state.umgebungStandort) {
      startLat = state.umgebungStandort.lat; startLng = state.umgebungStandort.lng;
    } else {
      const sRes = await fetch(
        `https://nominatim.openstreetmap.org/search?q=${encodeURIComponent(startName)}&format=json&limit=1`
      );
      const sData = await sRes.json();
      if (!sData.length) throw new Error('Startpunkt nicht gefunden — bitte oben einen Standort eingeben.');
      startLat = parseFloat(sData[0].lat); startLng = parseFloat(sData[0].lon);
    }

    // OSRM Routing (kostenlos, kein API-Key) — mit Zeitlimit und Wiederholversuch
    const osrmUrl = `https://router.project-osrm.org/route/v1/driving/${startLng},${startLat};${zielLng},${zielLat}?overview=full&geometries=geojson`;
    let routeData = null;
    for (let v = 1; v <= 2 && !routeData; v++) {
      try {
        const routeRes = await fetch(osrmUrl, { signal: AbortSignal.timeout(15000) });
        if (routeRes.ok) {
          const d = await routeRes.json();
          if (d.code === 'Ok' && d.routes?.length) routeData = d;
        }
      } catch (e) { /* nächster Versuch */ }
      if (!routeData && v < 2) await new Promise(r => setTimeout(r, 700));
    }
    if (!routeData) throw new Error('Route konnte nicht berechnet werden — Internetverbindung prüfen und erneut versuchen.');

    const route = routeData.routes[0];
    const distM = route.distance;
    const durS  = route.duration;
    const distStr = distM < 1000 ? `${Math.round(distM)} m` : `${(distM/1000).toFixed(1)} km`;
    const durStr  = durS < 60 ? `${Math.round(durS)} Sek.`
                  : durS < 3600 ? `${Math.round(durS/60)} Min.`
                  : `${Math.floor(durS/3600)}h ${Math.round((durS%3600)/60)} Min.`;

    state.routeDaten = { distanz: distStr, dauer: durStr, geoJson: route.geometry };
    state.routeLaden = false;

    // Route auf Karte zeichnen
    if (state.routeSchicht) {
      state.routeSchicht.clearLayers();
      const polyline = L.geoJSON(route.geometry, {
        style: { color: '#4F46E5', weight: 5, opacity: .8, dashArray: null }
      }).addTo(state.routeSchicht);
      if (state.karte) state.karte.fitBounds(polyline.getBounds(), { padding: [40, 40] });

      // Ziel-Marker
      const zielIcon = L.divIcon({
        html: '<div style="background:#DC2626;width:14px;height:14px;border-radius:50%;border:3px solid white;box-shadow:0 2px 8px rgba(220,38,38,.6)"></div>',
        iconSize:[14,14], iconAnchor:[7,7], className:''
      });
      L.marker([zielLat, zielLng], {icon: zielIcon}).addTo(state.routeSchicht)
        .bindPopup(`<strong>🔴 Ziel: ${esc(state.routeZiel)}</strong><br>${distStr} · ${durStr}`).openPopup();
    }

    render();
  } catch(e) {
    // Bei Fehler: alte Route verwerfen — sonst bleibt fälschlich die vorige
    // Strecke auf Karte und in der Ergebnis-Box stehen ("immer die gleiche Route").
    state.routeLaden = false;
    state.routeDaten = null;
    if (state.routeSchicht) { try { state.routeSchicht.clearLayers(); } catch {} }
    render();
    const fe = el('route-fehler');
    if (fe) { fe.textContent = e.message || 'Route konnte nicht berechnet werden. Adresse prüfen.'; fe.style.display = 'block'; }
  }
}

