// ===== FOTO-ALBUM (Fotos auf dem Gerät, gespeichert in IndexedDB) =====
let _albumDB = null;
function albumDBOeffnen() {
  return new Promise((resolve, reject) => {
    if (_albumDB) return resolve(_albumDB);
    const req = indexedDB.open('familienapp-album', 1);
    req.onupgradeneeded = e => {
      const db = e.target.result;
      if (!db.objectStoreNames.contains('fotos')) db.createObjectStore('fotos', { keyPath: 'id' });
    };
    req.onsuccess = e => { _albumDB = e.target.result; resolve(_albumDB); };
    req.onerror = () => reject(req.error);
  });
}
async function albumFotosLaden() {
  const db = await albumDBOeffnen();
  return new Promise(resolve => {
    const req = db.transaction('fotos', 'readonly').objectStore('fotos').getAll();
    req.onsuccess = () => resolve(req.result || []);
    req.onerror = () => resolve([]);
  });
}
async function albumFotoSpeichern(foto) {
  const db = await albumDBOeffnen();
  return new Promise((resolve, reject) => {
    const tx = db.transaction('fotos', 'readwrite');
    tx.objectStore('fotos').put(foto);
    tx.oncomplete = resolve;
    tx.onerror = () => reject(tx.error);
  });
}
async function albumFotoLoeschen(id) {
  const db = await albumDBOeffnen();
  return new Promise(resolve => {
    const tx = db.transaction('fotos', 'readwrite');
    tx.objectStore('fotos').delete(id);
    tx.oncomplete = resolve;
    tx.onerror = resolve;
  });
}

// Foto vor dem Speichern verkleinern — spart Speicherplatz
function albumBildKomprimieren(file) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => {
      const img = new Image();
      img.onload = () => {
        const max = 1280;
        let w = img.width, h = img.height;
        if (w > max || h > max) {
          if (w > h) { h = Math.round(h * max / w); w = max; }
          else { w = Math.round(w * max / h); h = max; }
        }
        const canvas = document.createElement('canvas');
        canvas.width = w; canvas.height = h;
        canvas.getContext('2d').drawImage(img, 0, 0, w, h);
        resolve(canvas.toDataURL('image/jpeg', 0.8));
      };
      img.onerror = reject;
      img.src = reader.result;
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
}

async function albumUpload(input) {
  const dateien = Array.from(input.files || []);
  if (!dateien.length) return;
  let ok = 0;
  for (const file of dateien) {
    if (!file.type.startsWith('image/')) continue;
    try {
      const bild = await albumBildKomprimieren(file);
      await albumFotoSpeichern({
        id: Date.now() + '-' + Math.random().toString(36).slice(2, 7),
        bild, titel: file.name.replace(/\.[^.]+$/, ''), datum: new Date().toISOString()
      });
      ok++;
    } catch (e) { /* einzelnes Foto übersprungen */ }
  }
  input.value = '';
  toast(ok > 0 ? `✓ ${ok} Foto${ok > 1 ? 's' : ''} gespeichert` : '⚠️ Kein Foto gespeichert');
  albumGridAktualisieren();
}

function renderAlbum() {
  setTimeout(() => albumGridAktualisieren(), 50);
  return `
  <div class="section-title">📷 Familien-Album</div>
  <p class="section-sub">Eure schönsten Momente — sicher auf diesem Gerät gespeichert</p>
  <label class="btn btn-primary" style="display:block;text-align:center;cursor:pointer;margin-bottom:.6rem">
    📷 Fotos hinzufügen
    <input type="file" accept="image/*" multiple onchange="albumUpload(this)" style="display:none" />
  </label>
  <div class="info-box blau" style="font-size:.8rem"><span class="ib-icon">🔒</span><div class="ib-text">Deine Fotos bleiben nur auf diesem Gerät und werden nirgends hochgeladen. Beim Wechsel des Handys werden sie nicht mit übertragen.</div></div>
  <div id="album-grid" style="margin-top:1rem"><div class="loading-spinner"><div class="spinner"></div><span>Album wird geladen…</span></div></div>`;
}

async function albumGridAktualisieren() {
  const c = el('album-grid');
  if (!c) return;
  const fotos = (await albumFotosLaden()).sort((a, b) => (b.datum || '').localeCompare(a.datum || ''));
  if (!fotos.length) {
    c.innerHTML = '<div class="info-box lila"><span class="ib-icon">📷</span><div class="ib-text"><strong>Noch keine Fotos.</strong> Tippe oben auf „Fotos hinzufügen", um euer Album zu starten.</div></div>';
    return;
  }
  c.innerHTML = '<div style="font-size:.78rem;color:var(--g500);margin-bottom:.5rem">' + fotos.length + ' Foto' + (fotos.length > 1 ? 's' : '') + ' im Album</div>'
    + '<div class="album-grid">' + fotos.map(f => `
    <div class="album-foto">
      <img src="${f.bild}" alt="${esc(f.titel || 'Foto')}" loading="lazy" onclick="albumVollbild('${f.id}')" />
      <button class="album-foto-del" onclick="albumLoeschenBestaetigen('${f.id}')">✕</button>
    </div>`).join('') + '</div>';
}

async function albumVollbild(id) {
  const f = (await albumFotosLaden()).find(x => x.id === id);
  if (!f) return;
  let o = document.getElementById('album-modal');
  if (o) o.remove();
  o = document.createElement('div');
  o.id = 'album-modal';
  o.className = 'album-modal';
  o.onclick = () => o.remove();
  o.innerHTML = `<button class="album-modal-close">✕</button><img src="${f.bild}" alt="${esc(f.titel || '')}" />`;
  document.body.appendChild(o);
}

async function albumLoeschenBestaetigen(id) {
  if (!confirm('Dieses Foto wirklich löschen?')) return;
  await albumFotoLoeschen(id);
  toast('✓ Foto gelöscht');
  albumGridAktualisieren();
}

// ===== MEDBOX — Medikamenten-Erinnerung =====
function _heuteISO() { const d = new Date(); return d.getFullYear() + '-' + String(d.getMonth()+1).padStart(2,'0') + '-' + String(d.getDate()).padStart(2,'0'); }
function medboxLaden() { try { return JSON.parse(localStorage.getItem('familienapp_medbox') || '[]'); } catch { return []; } }
function medboxSpeichern(l) { try { localStorage.setItem('familienapp_medbox', JSON.stringify(l)); } catch { toast('⚠️ Speicherfehler'); } }
function medGenommenLaden() { try { return JSON.parse(localStorage.getItem('familienapp_medbox_genommen') || '{}'); } catch { return {}; } }
function medGenommenSpeichern(g) { try { localStorage.setItem('familienapp_medbox_genommen', JSON.stringify(g)); } catch {} }

const MED_ZEITEN = [
  { id:'morgen', zeit:'08:00', label:'🌅 Morgens' },
  { id:'mittag', zeit:'12:00', label:'☀️ Mittags' },
  { id:'abend',  zeit:'18:00', label:'🌆 Abends' },
  { id:'nacht',  zeit:'22:00', label:'🌙 Nachts' }
];

function medHinzu() {
  const name = el('med-name')?.value.trim();
  if (!name) { toast('⚠️ Bitte einen Namen eingeben'); el('med-name')?.focus(); return; }
  const dosis = el('med-dosis')?.value.trim() || '';
  const zeiten = MED_ZEITEN.filter(z => el('med-zeit-' + z.id)?.checked).map(z => z.zeit);
  const l = medboxLaden();
  l.push({ id: Date.now(), name, dosis, zeiten });
  medboxSpeichern(l);
  toast('✓ Medikament gespeichert');
  if (zeiten.length && 'Notification' in window && Notification.permission === 'default') notificationsBerechtigung();
  render();
}
function medLoeschen(id) {
  if (!confirm('Dieses Medikament wirklich entfernen?')) return;
  medboxSpeichern(medboxLaden().filter(m => m.id !== id));
  toast('✓ Entfernt');
  render();
}
function medGenommenToggle(medId, zeit) {
  const g = medGenommenLaden();
  const k = medId + '_' + zeit + '_' + _heuteISO();
  if (g[k]) delete g[k]; else g[k] = true;
  medGenommenSpeichern(g);
  render();
}

// Medikamenten-Erinnerungen prüfen — wird von erinnerungenTick mitaufgerufen
function medboxErinnerungPruefen() {
  if (!('Notification' in window) || Notification.permission !== 'granted') return;
  const einst = einstellungenLaden();
  if (einst.notifAus === true || einst.notifMed === false) return;
  const meds = medboxLaden();
  if (!meds.length) return;
  const jetzt = new Date();
  const hhmm = String(jetzt.getHours()).padStart(2,'0') + ':' + String(jetzt.getMinutes()).padStart(2,'0');
  const heute = _heuteISO();
  let gefeuert = [];
  try { gefeuert = JSON.parse(localStorage.getItem('notif_med_gefeuert') || '[]'); } catch {}
  const genommen = medGenommenLaden();
  let geaendert = false;
  meds.forEach(m => {
    (m.zeiten || []).forEach(z => {
      const key = m.id + '|' + z + '|' + heute;
      if (z <= hhmm && !gefeuert.includes(key) && !genommen[m.id + '_' + z + '_' + heute]) {
        notificationZeigen('💊 ' + m.name, {
          body: (m.dosis ? m.dosis + ' — ' : '') + 'jetzt einnehmen (' + z + ' Uhr)',
          tag: 'med-' + key, zuSektion: 'medbox', requireInteraction: true
        });
        gefeuert.push(key);
        geaendert = true;
      }
    });
  });
  if (geaendert) {
    gefeuert = gefeuert.filter(k => k.endsWith('|' + heute)); // nur heutige behalten
    try { localStorage.setItem('notif_med_gefeuert', JSON.stringify(gefeuert)); } catch {}
  }
}

function renderMedbox() {
  const meds = medboxLaden();
  const genommen = medGenommenLaden();
  const heute = _heuteISO();
  const zLabel = z => (MED_ZEITEN.find(x => x.zeit === z)?.label || z);
  return `
  <div class="section-title">💊 Medikamenten-Erinnerung</div>
  <p class="section-sub">Behalte Medikamente und Einnahmezeiten im Blick</p>

  <div class="card" style="margin-bottom:1rem">
    <div style="font-weight:800;margin-bottom:.6rem">➕ Medikament hinzufügen</div>
    <div class="reg-feld"><label class="reg-label">Name</label><input id="med-name" class="reg-input" type="text" placeholder="z. B. Vitamin D" autocomplete="off" /></div>
    <div class="reg-feld"><label class="reg-label">Dosis (optional)</label><input id="med-dosis" class="reg-input" type="text" placeholder="z. B. 1 Tablette" autocomplete="off" /></div>
    <div class="reg-feld"><label class="reg-label">Einnahmezeiten</label>
      <div class="med-zeit-wahl">
        ${MED_ZEITEN.map(z => `<label class="med-zeit-opt"><input type="checkbox" id="med-zeit-${z.id}" /> ${z.label}</label>`).join('')}
      </div>
    </div>
    <button class="btn btn-primary" style="width:100%" onclick="medHinzu()">+ Speichern</button>
  </div>

  ${meds.length === 0 ? `
  <div class="info-box lila"><span class="ib-icon">💊</span><div class="ib-text"><strong>Noch keine Medikamente eingetragen.</strong> Lege oben das erste an — die App erinnert dich dann zur Einnahmezeit.</div></div>`
  : meds.map(m => `
    <div class="med-karte">
      <div class="med-karte-kopf">
        <div style="min-width:0">
          <div class="med-karte-name">💊 ${esc(m.name)}</div>
          ${m.dosis ? `<div class="med-karte-dosis">${esc(m.dosis)}</div>` : ''}
        </div>
        <button class="med-del" onclick="medLoeschen(${m.id})" title="Entfernen">✕</button>
      </div>
      ${(m.zeiten || []).length ? `<div class="med-zeiten">
        ${m.zeiten.map(z => {
          const ist = !!genommen[m.id + '_' + z + '_' + heute];
          return `<button class="med-dose${ist ? ' genommen' : ''}" onclick="medGenommenToggle(${m.id},'${z}')">
            <span>${zLabel(z)} · ${z}</span><span>${ist ? '✓ genommen' : '○ offen'}</span>
          </button>`;
        }).join('')}
      </div>` : '<div style="font-size:.8rem;color:var(--g500);margin-top:.4rem">Keine Einnahmezeit gewählt — es wird nicht erinnert.</div>'}
    </div>`).join('')}

  <div class="info-box orange" style="margin-top:1rem"><span class="ib-icon">⚠️</span><div class="ib-text">Die App ist eine Gedächtnisstütze und ersetzt keine ärztliche Anweisung. Dosierung und Einnahme immer wie mit Arzt oder Apotheke besprochen.</div></div>`;
}

// ===== TIERE & PFLANZEN ERKENNEN =====
// Foto eines Tieres oder einer Pflanze per KI-Bilderkennung bestimmen.

// Foto fürs Erkennen verkleinern — kleiner als Album, damit der Upload schnell bleibt
function erkennenBildKomprimieren(file) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => {
      const img = new Image();
      img.onload = () => {
        const max = 900;
        let w = img.width, h = img.height;
        if (w > max || h > max) {
          if (w > h) { h = Math.round(h * max / w); w = max; }
          else { w = Math.round(w * max / h); h = max; }
        }
        const canvas = document.createElement('canvas');
        canvas.width = w; canvas.height = h;
        canvas.getContext('2d').drawImage(img, 0, 0, w, h);
        resolve(canvas.toDataURL('image/jpeg', 0.82));
      };
      img.onerror = reject;
      img.src = reader.result;
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
}

async function erkennenFotoGewaehlt(input) {
  const file = (input.files || [])[0];
  if (!file) return;
  if (!file.type.startsWith('image/')) { toast('⚠️ Bitte ein Foto auswählen'); return; }
  try {
    state.erkennenBild = await erkennenBildKomprimieren(file);
    state.erkennenErgebnis = '';
    render();
  } catch (e) {
    toast('⚠️ Foto konnte nicht geladen werden');
  }
  input.value = '';
}

function erkennenZuruecksetzen() {
  state.erkennenBild = '';
  state.erkennenErgebnis = '';
  render();
}

async function erkennenStarten() {
  if (!state.erkennenBild) { toast('⚠️ Bitte zuerst ein Foto aufnehmen'); return; }
  const btn = el('erkennen-btn');
  const ausgabe = el('erkennen-ausgabe');
  if (btn) { btn.disabled = true; btn.textContent = '🔍 Wird erkannt…'; }
  if (ausgabe) ausgabe.innerHTML = '<div class="erkennen-laden">🔎 Das Bild wird analysiert – einen Moment…</div>';
  const prompt = 'Du bist ein Experte für Tier- und Pflanzenbestimmung. Bestimme, was auf diesem Foto zu sehen ist. ' +
    'Auf dem Foto kann auch nur ein Teil zu sehen sein — ein einzelnes Blatt, eine Blüte, eine Frucht, Rinde, ein Pilz, eine Feder oder eine Tierspur. ' +
    'Bestimme die Pflanze oder den Baum auch anhand eines einzelnen Blattes so genau wie möglich (achte auf Form, Rand und Blattadern). ' +
    'Antworte auf Deutsch, freundlich und für Familien verständlich, in genau diesem Format mit diesen Überschriften:\n' +
    '**Das ist:** Name auf Deutsch, möglichst genau, plus ob es ein Tier oder eine Pflanze ist.\n' +
    '**Beschreibung:** 2-3 Sätze – woran man es erkennt, wo es vorkommt.\n' +
    '**Für Familien wichtig:** Ist es giftig, stechend oder gefährlich für Kinder oder Haustiere? Klar und ehrlich sagen. Wenn harmlos, das auch sagen.\n' +
    '**Tipp:** Ein praktischer Tipp – Pflege bei Pflanzen, Verhalten bei Tieren.\n' +
    'Wenn du dir nicht sicher bist, sage das ehrlich und nenne die wahrscheinlichste Möglichkeit. ' +
    'Wenn auf dem Foto kein Tier und keine Pflanze zu erkennen ist, sage das freundlich.';
  try {
    const res = await fetch('https://text.pollinations.ai/openai', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        model: 'openai',
        private: true,
        messages: [{
          role: 'user',
          content: [
            { type: 'text', text: prompt },
            { type: 'image_url', image_url: { url: state.erkennenBild } }
          ]
        }]
      }),
      signal: AbortSignal.timeout(45000)
    });
    if (!res.ok) throw new Error('http ' + res.status);
    const data = await res.json();
    const text = (data && data.choices && data.choices[0] && data.choices[0].message && data.choices[0].message.content || '').trim();
    if (!text) throw new Error('leer');
    state.erkennenErgebnis = text;
  } catch (e) {
    state.erkennenErgebnis = '__FEHLER__';
  }
  render();
}

// Einfaches Markdown für die Erkennungs-Antwort: **fett** und Zeilenumbrüche
function erkennenTextFormat(text) {
  return esc(text)
    .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
    .replace(/\r?\n/g, '<br>');
}

function renderErkennen() {
  const bild = state.erkennenBild;
  const erg = state.erkennenErgebnis;
  return `
  <div class="section-title">🌿 Tiere & Pflanzen erkennen</div>
  <p class="section-sub">Foto aufnehmen – die App bestimmt, was darauf zu sehen ist</p>

  <div class="card" style="margin-bottom:1rem">
    ${bild ? `
      <div class="erkennen-vorschau"><img src="${bild}" alt="Aufgenommenes Foto" /></div>
      <div class="erkennen-aktionen">
        <button class="btn btn-primary" id="erkennen-btn" style="flex:1" onclick="erkennenStarten()">🔍 Jetzt erkennen</button>
        <button class="btn btn-outline" onclick="erkennenZuruecksetzen()">✕ Neues Foto</button>
      </div>
    ` : `
      <label class="erkennen-upload">
        <input type="file" accept="image/*" capture="environment" onchange="erkennenFotoGewaehlt(this)" hidden />
        <div class="erkennen-upload-icon">📷</div>
        <div class="erkennen-upload-text">Foto aufnehmen oder auswählen</div>
        <div class="erkennen-upload-sub">Tier, Pflanze, einzelnes Blatt, Blüte, Pilz …</div>
      </label>
    `}
  </div>

  <div id="erkennen-ausgabe">
    ${erg === '__FEHLER__' ? `
      <div class="info-box orange"><span class="ib-icon">⚠️</span><div class="ib-text"><strong>Erkennung nicht möglich.</strong> Bitte Internetverbindung prüfen und es noch einmal versuchen – am besten mit einem scharfen, gut beleuchteten Foto.</div></div>`
    : erg ? `
      <div class="erkennen-ergebnis">
        <div class="erkennen-ergebnis-titel">🔎 Erkennungs-Ergebnis</div>
        <div class="erkennen-ergebnis-text">${erkennenTextFormat(erg)}</div>
      </div>` : ''}
  </div>

  <div class="info-box blau" style="margin-top:1rem"><span class="ib-icon">💡</span><div class="ib-text">Die Erkennung ist eine KI-Schätzung und kann sich irren. Bei giftigen Pflanzen, Pilzen oder unbekannten Tieren im Zweifel <strong>nichts anfassen oder essen</strong> und Fachleute fragen.</div></div>`;
}

// ===== ERSTE HILFE =====
// Bild-gestützte Schritt-für-Schritt-Anleitungen für Familien-Notfälle.
function ersteHilfeOeffnen(id) {
  state.ehThema = id;
  render();
  window.scrollTo({ top: 0, behavior: 'smooth' });
}
function ersteHilfeZurueck() {
  state.ehThema = null;
  render();
}

function renderErsteHilfe() {
  const daten = (typeof ERSTE_HILFE !== 'undefined') ? ERSTE_HILFE : [];
  // Detailansicht eines Themas
  if (state.ehThema) {
    const t = daten.find(x => x.id === state.ehThema);
    if (t) return renderErsteHilfeDetail(t);
    state.ehThema = null;
  }
  // Übersicht: Notruf-Banner + Themen-Kacheln
  return `
  <div class="section-title">🚑 Erste Hilfe</div>
  <p class="section-sub">Ruhig bleiben — Schritt für Schritt mit Bild-Anleitung</p>

  <a href="tel:112" class="eh-notruf">
    <div class="eh-notruf-icon">📞</div>
    <div><div class="eh-notruf-zahl">Notruf 112</div>
    <div class="eh-notruf-sub">Tippen, um direkt anzurufen</div></div>
  </a>

  <div class="eh-grid">
    ${daten.map(t => `
      <button class="eh-kachel${t.notfall ? ' notfall' : ''}" onclick="ersteHilfeOeffnen('${t.id}')">
        <span class="eh-kachel-emoji">${t.emoji}</span>
        <span class="eh-kachel-titel">${esc(t.titel)}</span>
        <span class="eh-kachel-kurz">${esc(t.kurz)}</span>
        ${t.notfall ? '<span class="eh-kachel-tag">Notfall</span>' : ''}
      </button>`).join('')}
  </div>

  <div class="info-box orange" style="margin-top:1rem"><span class="ib-icon">⚠️</span><div class="ib-text">Diese Anleitungen ersetzen keinen Erste-Hilfe-Kurs. Bei jedem ernsten Notfall zuerst die <strong>112</strong> rufen.</div></div>`;
}

function renderErsteHilfeDetail(t) {
  return `
  <button class="eh-zurueck" onclick="ersteHilfeZurueck()">‹ Alle Themen</button>
  <div class="eh-detail-kopf${t.notfall ? ' notfall' : ''}">
    <span class="eh-detail-emoji">${t.emoji}</span>
    <div><div class="eh-detail-titel">${esc(t.titel)}</div>
    <div class="eh-detail-kurz">${esc(t.kurz)}</div></div>
  </div>

  ${t.notfall ? `<a href="tel:112" class="eh-notruf klein">
    <div class="eh-notruf-icon">📞</div>
    <div><div class="eh-notruf-zahl">Notruf 112 anrufen</div>
    <div class="eh-notruf-sub">Bei diesem Notfall sofort Hilfe rufen</div></div>
  </a>` : ''}

  <div class="eh-schritte">
    ${t.schritte.map((s, i) => `
      <div class="eh-schritt">
        <div class="eh-schritt-nr">${i + 1}</div>
        <div class="eh-schritt-icon">${s.icon}</div>
        <div class="eh-schritt-text">
          <div class="eh-schritt-titel">${esc(s.titel)}</div>
          <div class="eh-schritt-body">${esc(s.text)}</div>
        </div>
      </div>`).join('')}
  </div>

  <div class="info-box orange" style="margin-top:1rem"><span class="ib-icon">❗</span><div class="ib-text">${esc(t.achtung)}</div></div>
  <div class="info-box blau" style="margin-top:.6rem"><span class="ib-icon">🎓</span><div class="ib-text">Am sichersten hilfst du nach einem echten Erste-Hilfe-Kurs. Kurse gibt es u. a. beim DRK, ASB, bei den Maltesern und Johannitern.</div></div>`;
}

// ===== WISSEN =====
function wissenKatWaehlen(k) { state.wissenKat = k; render(); }

function renderWissen() {
  const fakten = typeof WISSEN_FAKTEN !== 'undefined' ? WISSEN_FAKTEN : [];
  if (!fakten.length) return '<div class="info-box orange"><span class="ib-icon">⚠️</span><div class="ib-text">Wissens-Daten sind nicht verfügbar.</div></div>';
  const jahresStart = new Date(new Date().getFullYear(), 0, 0);
  const tag = Math.floor((Date.now() - jahresStart) / 86400000);
  const heute = fakten[tag % fakten.length];
  const kats = [...new Set(fakten.map(f => f.kategorie))];
  const aktiv = (state.wissenKat && kats.includes(state.wissenKat)) ? state.wissenKat : 'alle';
  const gefiltert = aktiv === 'alle' ? fakten : fakten.filter(f => f.kategorie === aktiv);
  return `
  <div class="section-title">💡 Wissen</div>
  <p class="section-sub">Jeden Tag ein neuer, echter Wissens-Fakt für die ganze Familie</p>

  <div class="wissen-heute">
    <div class="wissen-heute-label">🌅 Wissen des Tages</div>
    <div class="wissen-heute-text">${esc(heute.text)}</div>
    <div class="wissen-heute-kat">📚 ${esc(heute.kategorie)}</div>
  </div>

  <div class="block-title" style="margin-top:1.5rem">Zum Stöbern — ${fakten.length} Fakten</div>
  <div class="tipps-filter">
    <button class="tipps-filter-btn ${aktiv==='alle'?'aktiv':''}" onclick="wissenKatWaehlen('alle')">Alle</button>
    ${kats.map(k => `<button class="tipps-filter-btn ${aktiv===k?'aktiv':''}" onclick="wissenKatWaehlen('${k}')">${esc(k)}</button>`).join('')}
  </div>
  <div class="grid-2">
    ${gefiltert.map(f => `
      <div class="tipp-karte">
        <div class="tipp-karte-titel">💡 ${esc(f.kategorie)}</div>
        <div class="tipp-karte-text">${esc(f.text)}</div>
      </div>`).join('')}
  </div>`;
}

// ===== SPRACHÜBERSETZER =====
const UEB_SPRACHEN = [
  { code:'de', name:'Deutsch',        bcp:'de-DE' },
  { code:'en', name:'Englisch',       bcp:'en-US' },
  { code:'tr', name:'Türkisch',       bcp:'tr-TR' },
  { code:'ar', name:'Arabisch',       bcp:'ar-SA' },
  { code:'ru', name:'Russisch',       bcp:'ru-RU' },
  { code:'uk', name:'Ukrainisch',     bcp:'uk-UA' },
  { code:'pl', name:'Polnisch',       bcp:'pl-PL' },
  { code:'fr', name:'Französisch',    bcp:'fr-FR' },
  { code:'es', name:'Spanisch',       bcp:'es-ES' },
  { code:'it', name:'Italienisch',    bcp:'it-IT' },
  { code:'ro', name:'Rumänisch',      bcp:'ro-RO' },
  { code:'nl', name:'Niederländisch', bcp:'nl-NL' }
];
function uebBcp(code) { return (UEB_SPRACHEN.find(s => s.code === code)?.bcp) || code; }
let _uebLetztesErgebnis = '';

async function uebersetzeMyMemory(text, von, nach) {
  try {
    const url = `https://api.mymemory.translated.net/get?q=${encodeURIComponent(text)}&langpair=${von}|${nach}`;
    const res = await fetch(url, { signal: AbortSignal.timeout(12000) });
    if (!res.ok) return null;
    const d = await res.json();
    const t = d?.responseData?.translatedText;
    if (t && !/^(MYMEMORY WARNING|INVALID|'|")/i.test(t.trim())) return t.trim();
    return null;
  } catch { return null; }
}
async function uebersetzePollinations(text, von, nach) {
  const name = c => (UEB_SPRACHEN.find(s => s.code === c)?.name || c);
  const prompt = `Übersetze den folgenden Text von ${name(von)} nach ${name(nach)}. Gib NUR die reine Übersetzung zurück, ohne Kommentar und ohne Anführungszeichen:\n\n${text}`;
  try {
    const res = await fetch('https://text.pollinations.ai/' + encodeURIComponent(prompt) + '?model=openai&private=true', { signal: AbortSignal.timeout(20000) });
    if (!res.ok) return null;
    const t = (await res.text()).trim();
    return t || null;
  } catch { return null; }
}
async function uebersetzungStarten() {
  const text = (el('ueb-text')?.value || '').trim();
  const von = el('ueb-von')?.value || 'de';
  const nach = el('ueb-nach')?.value || 'en';
  const out = el('ueb-ergebnis');
  if (!out) return;
  if (!text) { toast('⚠️ Bitte einen Text eingeben'); return; }
  if (von === nach) { toast('⚠️ Bitte zwei verschiedene Sprachen wählen'); return; }
  out.innerHTML = '<div class="rezept-laden" style="padding:1.25rem;text-align:center">⏳ Übersetze…</div>';
  let ergebnis = await uebersetzeMyMemory(text, von, nach);
  if (!ergebnis) ergebnis = await uebersetzePollinations(text, von, nach);
  if (ergebnis) {
    _uebLetztesErgebnis = ergebnis;
    out.innerHTML = `
      <div class="ueb-ergebnis-box">
        <div class="ueb-ergebnis-text">${esc(ergebnis)}</div>
        <div class="ueb-ergebnis-aktionen">
          <button class="btn btn-sm" onclick="uebersetzungVorlesen()">🔊 Vorlesen</button>
          <button class="btn btn-sm" onclick="uebersetzungKopieren()">📋 Kopieren</button>
        </div>
      </div>`;
  } else {
    out.innerHTML = '<div class="info-box orange"><span class="ib-icon">⚠️</span><div class="ib-text">Übersetzung gerade nicht möglich — bitte Internetverbindung prüfen und erneut versuchen.</div></div>';
  }
}
function uebersetzerTauschen() {
  const vonEl = el('ueb-von'), nachEl = el('ueb-nach');
  if (!vonEl || !nachEl) return;
  const tmp = vonEl.value; vonEl.value = nachEl.value; nachEl.value = tmp;
}
function uebersetzungVorlesen() {
  if (!window.speechSynthesis || !_uebLetztesErgebnis) { toast('⚠️ Vorlesen nicht möglich'); return; }
  speechSynthesis.cancel();
  const u = new SpeechSynthesisUtterance(_uebLetztesErgebnis);
  u.lang = uebBcp(el('ueb-nach')?.value || 'en');
  stimmeAnwenden(u);
  speechSynthesis.speak(u);
}
// Spracheingabe: gesprochenen Text in das Übersetzungsfeld schreiben und direkt übersetzen
// — nutzt den gemeinsamen Helfer spracheErkennen()
function uebersetzungSprechen() {
  spracheErkennen({
    lang: uebBcp(el('ueb-von')?.value || 'de'),
    btn: '#ueb-mic',
    hinweis: '🎤 Jetzt sprechen — zum Stoppen Mikro erneut tippen',
    onText: text => {
      const feld = el('ueb-text');
      if (feld) feld.value = text;
      toast('✓ ' + text);
      uebersetzungStarten();
    }
  });
}
function uebersetzungKopieren() {
  if (!_uebLetztesErgebnis) return;
  try { navigator.clipboard.writeText(_uebLetztesErgebnis); toast('✓ Übersetzung kopiert'); }
  catch { toast('⚠️ Kopieren nicht möglich'); }
}
function renderUebersetzer() {
  const sel = (id, vorgabe) => `<select id="${id}" class="reg-select">${UEB_SPRACHEN.map(s => `<option value="${s.code}"${s.code === vorgabe ? ' selected' : ''}>${s.name}</option>`).join('')}</select>`;
  return `
  <div class="section-title">🌐 Übersetzer</div>
  <p class="section-sub">Texte schnell in andere Sprachen übersetzen — 12 Sprachen</p>
  <div class="card">
    <div class="ueb-sprachzeile">
      ${sel('ueb-von', 'de')}
      <button class="ueb-tausch" onclick="uebersetzerTauschen()" title="Sprachen tauschen">⇄</button>
      ${sel('ueb-nach', 'en')}
    </div>
    <textarea id="ueb-text" class="reg-input" rows="4" placeholder="Text eingeben oder über das Mikrofon sprechen…" style="margin-top:.6rem;resize:vertical;font-family:inherit"></textarea>
    <div class="ueb-aktionszeile">
      <button class="btn btn-outline ueb-mic" id="ueb-mic" onclick="uebersetzungSprechen()" title="Text sprechen">🎤 Sprechen</button>
      <button class="btn btn-primary" style="flex:1" onclick="uebersetzungStarten()">🌐 Übersetzen</button>
    </div>
  </div>
  <div id="ueb-ergebnis" style="margin-top:1rem"></div>
  <div class="info-box blau" style="margin-top:1rem;font-size:.8rem"><span class="ib-icon">ℹ️</span><div class="ib-text">Sprechen und Vorlesen funktionieren in den meisten Browsern. Die Übersetzung wird online erstellt und ist eine gute Alltagshilfe. Bei wichtigen Dokumenten (Ämter, Verträge) lieber einen vereidigten Übersetzer fragen.</div></div>`;
}

// ===== KONTAKTE =====
const KONTAKT_KATS = [
  { id:'familie',  label:'Familie & Freunde',   icon:'👨‍👩‍👧', farbe:'#EC4899' },
  { id:'arzt',     label:'Ärzte & Gesundheit',  icon:'🩺',      farbe:'#DC2626' },
  { id:'schule',   label:'Schule & Kita',       icon:'🎒',      farbe:'#2563EB' },
  { id:'notfall',  label:'Notfall & Wichtiges', icon:'🆘',      farbe:'#B91C1C' },
  { id:'sonstige', label:'Sonstige',            icon:'📇',      farbe:'#7C3AED' }
];
function kontakteLaden() { try { return JSON.parse(localStorage.getItem('familienapp_kontakte') || '[]'); } catch { return []; } }
function kontakteSpeichern(l) { try { localStorage.setItem('familienapp_kontakte', JSON.stringify(l)); } catch { toast('⚠️ Speicherfehler'); } }

function kontaktHinzu() {
  const name = el('kontakt-name')?.value.trim();
  if (!name) { toast('⚠️ Bitte einen Namen eingeben'); el('kontakt-name')?.focus(); return; }
  const k = {
    id: Date.now(),
    name,
    kategorie: el('kontakt-kat')?.value || 'sonstige',
    telefon: el('kontakt-tel')?.value.trim() || '',
    email: el('kontakt-email')?.value.trim() || '',
    notiz: el('kontakt-notiz')?.value.trim() || ''
  };
  const l = kontakteLaden();
  l.push(k);
  kontakteSpeichern(l);
  toast('✓ Kontakt gespeichert');
  render();
}
function kontaktLoeschen(id) {
  if (!confirm('Diesen Kontakt wirklich löschen?')) return;
  kontakteSpeichern(kontakteLaden().filter(k => k.id !== id));
  toast('✓ Kontakt gelöscht');
  render();
}

function renderKontakte() {
  const kontakte = kontakteLaden();
  return `
  <div class="section-title">📇 Kontakte</div>
  <p class="section-sub">Alle wichtigen Nummern der Familie an einem Ort</p>

  <div class="info-box" style="background:#FEE2E2;border:1px solid #FCA5A5">
    <span class="ib-icon">🆘</span>
    <div class="ib-text"><strong>Notruf 112</strong> (Feuerwehr & Rettung) · <strong>110</strong> (Polizei) · <strong>116117</strong> (ärztlicher Bereitschaftsdienst) · <strong>116111</strong> (Kinder-Sorgentelefon)</div>
  </div>

  <div class="card" style="margin:1rem 0">
    <div style="font-weight:800;margin-bottom:.65rem">➕ Neuen Kontakt anlegen</div>
    <div class="reg-feld"><label class="reg-label">Name</label><input id="kontakt-name" class="reg-input" type="text" placeholder="z. B. Kinderärztin Dr. Müller" autocomplete="off" /></div>
    <div class="grid-2">
      <div class="reg-feld"><label class="reg-label">Kategorie</label>
        <select id="kontakt-kat" class="reg-select">${KONTAKT_KATS.map(k => `<option value="${k.id}">${k.icon} ${k.label}</option>`).join('')}</select>
      </div>
      <div class="reg-feld"><label class="reg-label">Telefon</label><input id="kontakt-tel" class="reg-input" type="tel" placeholder="z. B. 030 1234567" autocomplete="off" /></div>
    </div>
    <div class="reg-feld"><label class="reg-label">E-Mail (optional)</label><input id="kontakt-email" class="reg-input" type="email" placeholder="name@beispiel.de" autocomplete="off" /></div>
    <div class="reg-feld"><label class="reg-label">Notiz (optional)</label><input id="kontakt-notiz" class="reg-input" type="text" placeholder="z. B. Sprechzeiten, Adresse" autocomplete="off" /></div>
    <button class="btn btn-primary" style="width:100%" onclick="kontaktHinzu()">+ Kontakt speichern</button>
  </div>

  ${kontakte.length === 0 ? `
  <div class="info-box lila"><span class="ib-icon">📇</span><div class="ib-text"><strong>Noch keine Kontakte.</strong> Lege oben Arzt, Schule, Familie oder wichtige Notfall-Kontakte an — dann sind sie immer griffbereit.</div></div>`
  : KONTAKT_KATS.map(kat => {
      const inKat = kontakte.filter(k => k.kategorie === kat.id);
      if (!inKat.length) return '';
      return `
      <div class="block-title" style="margin-top:1.25rem">${kat.icon} ${kat.label}</div>
      ${inKat.map(k => `
        <div class="kontakt-karte" style="border-left:4px solid ${kat.farbe}">
          <div class="kontakt-karte-info">
            <div class="kontakt-karte-name">${esc(k.name)}</div>
            ${k.telefon ? `<div class="kontakt-karte-zeile">📞 ${esc(k.telefon)}</div>` : ''}
            ${k.email ? `<div class="kontakt-karte-zeile">✉️ ${esc(k.email)}</div>` : ''}
            ${k.notiz ? `<div class="kontakt-karte-zeile" style="color:var(--g500)">📝 ${esc(k.notiz)}</div>` : ''}
          </div>
          <div class="kontakt-karte-aktionen">
            ${k.telefon ? `<a href="tel:${esc(k.telefon.replace(/\s/g, ''))}" class="kontakt-btn" style="background:${kat.farbe}" title="Anrufen">📞</a>` : ''}
            ${k.email ? `<a href="mailto:${esc(k.email)}" class="kontakt-btn" style="background:#64748B" title="E-Mail">✉️</a>` : ''}
            <button class="kontakt-btn kontakt-btn-del" onclick="kontaktLoeschen(${k.id})" title="Löschen">✕</button>
          </div>
        </div>`).join('')}`;
    }).join('')}`;
}

// ===== ZYKLUSKALENDER =====
function zyklusLaden() { try { return JSON.parse(localStorage.getItem('familienapp_zyklus')) || null; } catch { return null; } }
function zyklusSpeichern(d) { try { localStorage.setItem('familienapp_zyklus', JSON.stringify(d)); } catch {} }

function zyklusBerechnen() {
  const datum = el('zyklus-datum')?.value;
  const laenge = parseInt(el('zyklus-laenge')?.value) || 28;
  const dauer = parseInt(el('zyklus-dauer')?.value) || 5;
  if (!datum) { toast('⚠️ Bitte den ersten Tag der letzten Periode eingeben'); return; }
  zyklusSpeichern({
    letztePeriode: datum,
    zyklusLaenge: Math.max(20, Math.min(45, laenge)),
    periodenDauer: Math.max(2, Math.min(10, dauer))
  });
  toast('✓ Zyklus gespeichert');
  render();
}
function zyklusZuruecksetzen() {
  if (!confirm('Zyklus-Daten wirklich löschen?')) return;
  localStorage.removeItem('familienapp_zyklus');
  render();
}

// --- Stimmungs-Tagebuch ---
const ZYKLUS_STIMMUNGEN = [
  { key:'gut',     icon:'😊', label:'Gut drauf' },
  { key:'neutral', icon:'😐', label:'Neutral' },
  { key:'traurig', icon:'😢', label:'Niedergeschlagen' },
  { key:'schmerz', icon:'😣', label:'Schmerzen' },
  { key:'muede',   icon:'😴', label:'Erschöpft' },
  { key:'gereizt', icon:'😤', label:'Gereizt' },
  { key:'energie', icon:'🤩', label:'Voller Energie' }
];
function zyklusEmotionenLaden() { try { return JSON.parse(localStorage.getItem('familienapp_zyklus_emotionen') || '{}'); } catch { return {}; } }
function zyklusEmotionSetzen(key) {
  const e = zyklusEmotionenLaden();
  const heuteKey = new Date().toISOString().slice(0, 10);
  if (e[heuteKey] === key) delete e[heuteKey]; else e[heuteKey] = key;
  try { localStorage.setItem('familienapp_zyklus_emotionen', JSON.stringify(e)); } catch {}
  render();
}
function zyklusEmotionBlock() {
  const e = zyklusEmotionenLaden();
  const heuteMood = e[new Date().toISOString().slice(0, 10)];
  const tage = [];
  for (let i = 6; i >= 0; i--) {
    const dt = new Date(); dt.setDate(dt.getDate() - i);
    const m = ZYKLUS_STIMMUNGEN.find(s => s.key === e[dt.toISOString().slice(0, 10)]);
    tage.push({ label: dt.toLocaleDateString('de-DE', { weekday: 'short' }), icon: m ? m.icon : '·' });
  }
  return `
  <div class="card" style="margin-top:1rem">
    <div style="font-weight:800;margin-bottom:.55rem">🌈 Wie fühlst du dich heute?</div>
    <div style="display:flex;flex-wrap:wrap;gap:.4rem">
      ${ZYKLUS_STIMMUNGEN.map(s => `
        <button class="zyklus-mood${heuteMood === s.key ? ' aktiv' : ''}" onclick="zyklusEmotionSetzen('${s.key}')">
          <span style="font-size:1.4rem">${s.icon}</span><span>${esc(s.label)}</span>
        </button>`).join('')}
    </div>
    <div style="display:flex;justify-content:space-between;margin-top:.85rem;gap:.3rem">
      ${tage.map(t => `<div style="text-align:center;flex:1">
        <div style="font-size:1.2rem">${t.icon}</div>
        <div style="font-size:.62rem;color:var(--g500);font-weight:700">${t.label}</div>
      </div>`).join('')}
    </div>
    <div style="font-size:.72rem;color:var(--g500);margin-top:.5rem">Deine Stimmung über die Woche — so erkennst du Muster im Zyklus. Tippe erneut, um die Auswahl zu entfernen.</div>
  </div>`;
}

function zyklusFormular(d) {
  return `
  <div class="card" style="margin-top:1rem">
    <div style="font-weight:800;margin-bottom:.65rem">🌸 ${d ? 'Zyklus-Daten aktualisieren' : 'Zyklus eintragen'}</div>
    <div class="reg-feld">
      <label class="reg-label">Erster Tag der letzten Periode</label>
      <input type="date" id="zyklus-datum" class="reg-input" value="${d ? d.letztePeriode : ''}" />
    </div>
    <div class="grid-2">
      <div class="reg-feld">
        <label class="reg-label">Zykluslänge (Tage)</label>
        <input type="number" id="zyklus-laenge" class="reg-input" min="20" max="45" value="${d ? d.zyklusLaenge : 28}" />
      </div>
      <div class="reg-feld">
        <label class="reg-label">Dauer der Periode (Tage)</label>
        <input type="number" id="zyklus-dauer" class="reg-input" min="2" max="10" value="${d ? d.periodenDauer : 5}" />
      </div>
    </div>
    <button class="btn btn-primary" style="width:100%;margin-top:.4rem" onclick="zyklusBerechnen()">${d ? '✓ Aktualisieren' : '✓ Zyklus berechnen'}</button>
    ${d ? '<button class="btn btn-outline btn-sm" style="width:100%;margin-top:.5rem" onclick="zyklusZuruecksetzen()">Daten löschen</button>' : ''}
  </div>`;
}

function renderZykluskalender() {
  const d = zyklusLaden();
  if (!d) {
    return `
    <div class="info-box lila"><span class="ib-icon">🌸</span><div class="ib-text"><strong>Zykluskalender:</strong> Behalte deinen Zyklus im Blick — hilfreich bei Kinderwunsch und um deinen Körper besser zu verstehen. Deine Daten bleiben nur auf diesem Gerät.</div></div>
    ${zyklusFormular(null)}
    ${zyklusEmotionBlock()}
    <div class="info-box orange" style="margin-top:1rem"><span class="ib-icon">ℹ️</span><div class="ib-text">Der Zykluskalender dient der <strong>Orientierung</strong> und ist <strong>keine Verhütungsmethode</strong>. Jeder Zyklus ist unterschiedlich.</div></div>`;
  }
  const tag = 86400000;
  const heute = new Date(); heute.setHours(0,0,0,0);
  const lp = new Date(d.letztePeriode + 'T00:00:00');
  const tageSeit = Math.floor((heute - lp) / tag);
  const zyklen = tageSeit >= 0 ? Math.floor(tageSeit / d.zyklusLaenge) : 0;
  const zyklusStart = new Date(lp.getTime() + zyklen * d.zyklusLaenge * tag);
  const zyklustag = Math.floor((heute - zyklusStart) / tag) + 1;
  const naechstePeriode = new Date(zyklusStart.getTime() + d.zyklusLaenge * tag);
  const eisprungDatum = new Date(zyklusStart.getTime() + (d.zyklusLaenge - 14 - 1) * tag);
  const fruchtbarVon = new Date(eisprungDatum.getTime() - 5 * tag);
  const fruchtbarBis = new Date(eisprungDatum.getTime() + 1 * tag);
  const fmt = dt => dt.toLocaleDateString('de-DE', { weekday:'short', day:'2-digit', month:'short' });
  const tageBisPeriode = Math.round((naechstePeriode - heute) / tag);
  const istFruchtbar = heute >= fruchtbarVon && heute <= fruchtbarBis;
  const istPeriode = zyklustag >= 1 && zyklustag <= d.periodenDauer;

  let statusBox;
  if (istPeriode) {
    statusBox = '<div class="info-box" style="background:#FEE2E2;border:1px solid #FCA5A5"><span class="ib-icon">🩸</span><div class="ib-text"><strong>Periode:</strong> Du bist vermutlich gerade in den ersten Zyklustagen (Tag ' + zyklustag + ').</div></div>';
  } else if (istFruchtbar) {
    statusBox = '<div class="info-box" style="background:#DCFCE7;border:1px solid #86EFAC"><span class="ib-icon">🌱</span><div class="ib-text"><strong>Fruchtbare Tage:</strong> Heute ist die Wahrscheinlichkeit, schwanger zu werden, erhöht.</div></div>';
  } else {
    statusBox = '<div class="info-box lila"><span class="ib-icon">📅</span><div class="ib-text">Heute ist <strong>Zyklustag ' + zyklustag + '</strong> von ' + d.zyklusLaenge + '.</div></div>';
  }

  const statKarte = (icon, titel, wert) => `
    <div style="flex:1;min-width:140px;background:white;border:1px solid #E5E7EB;border-radius:12px;padding:.75rem .85rem">
      <div style="font-size:1.4rem">${icon}</div>
      <div style="font-size:.7rem;text-transform:uppercase;letter-spacing:.04em;color:var(--g500);font-weight:800;margin-top:.2rem">${titel}</div>
      <div style="font-size:.92rem;font-weight:800;margin-top:.1rem">${wert}</div>
    </div>`;

  return `
  ${statusBox}
  <div style="display:flex;flex-wrap:wrap;gap:.6rem;margin:1rem 0">
    ${statKarte('🔵', 'Zyklustag', zyklustag + ' / ' + d.zyklusLaenge)}
    ${statKarte('🩸', 'Nächste Periode', fmt(naechstePeriode) + ' (in ' + tageBisPeriode + ' T.)')}
    ${statKarte('🌱', 'Fruchtbare Tage', fmt(fruchtbarVon) + ' – ' + fmt(fruchtbarBis))}
    ${statKarte('⭐', 'Eisprung (ca.)', fmt(eisprungDatum))}
  </div>
  ${zyklusEmotionBlock()}
  ${zyklusFormular(d)}
  <div class="info-box orange" style="margin-top:1rem"><span class="ib-icon">ℹ️</span><div class="ib-text">Alle Angaben sind <strong>Schätzungen zur Orientierung</strong> und keine Verhütungsmethode. Bei unregelmäßigem Zyklus, Kinderwunsch über längere Zeit oder Beschwerden hilft die Frauenärztin weiter.</div></div>`;
}

function renderSchwangerschaft() {
  const tab = state.schwangerschaftTab || 'wochen';
  const tabs = [
    {id:'wochen', label:'Wochenüberblick'},
    {id:'zyklus', label:'Zykluskalender'},
    {id:'untersuchungen', label:'Untersuchungen'},
    {id:'ernaehrung', label:'Ernährung'},
    {id:'stillen', label:'Stillen'},
    {id:'behoerden', label:'Behörden & Formulare'},
    {id:'kliniken', label:'Kliniken in der Nähe'},
    {id:'vorbereitung', label:'Vorbereitung'}
  ];

  let inhalt = '';
  if (tab === 'wochen') inhalt = renderSchwangerschaftWochen();
  else if (tab === 'zyklus') inhalt = renderZykluskalender();
  else if (tab === 'untersuchungen') inhalt = renderSchwangerschaftUntersuchungen();
  else if (tab === 'ernaehrung') inhalt = renderSchwangerschaftErnaehrung();
  else if (tab === 'stillen') inhalt = renderSchwangerschaftStillen();
  else if (tab === 'behoerden') inhalt = renderSchwangerschaftBehoerden();
  else if (tab === 'kliniken') inhalt = renderSchwangerschaftKliniken();
  else if (tab === 'vorbereitung') inhalt = renderSchwangerschaftVorbereitung();

  return `
  <div class="news-hero">
    <div class="news-hero-bg" style="background-image:url('https://images.unsplash.com/photo-1518795058687-d77ed3293a98?w=800&q=70')"></div>
    <div class="news-hero-overlay"></div>
    <div class="news-hero-inhalt">
      <div style="font-size:1.4rem;font-weight:800;margin-bottom:.3rem">Schwangerschaft</div>
      <div style="font-size:.85rem;opacity:.9">Alles für 9 Monate: Untersuchungen, Behörden, Vorbereitung</div>
    </div>
  </div>
  <div class="news-kat-tabs">
    ${tabs.map(t=>`<button class="news-kat-btn ${tab===t.id?'aktiv':''}" onclick="schwangerschaftTabWaehlen('${t.id}')">${t.label}</button>`).join('')}
  </div>
  ${inhalt}`;
}

